let dashboardMountCtx = null;
let dashGradientSeq = 0;
let dashChartContextMenuEl = null;
let dashChartContextMenuCleanup = null;
let dashBalanceClickCleanup = null;

function dashCloseChartContextMenu() {
  dashChartContextMenuCleanup?.();
  dashChartContextMenuCleanup = null;
  dashChartContextMenuEl?.remove();
  dashChartContextMenuEl = null;
}

function dashPositionContextMenu(menu, clientX, clientY) {
  menu.style.visibility = 'hidden';
  menu.style.left = '0';
  menu.style.top = '0';
  document.body.appendChild(menu);
  const rect = menu.getBoundingClientRect();
  const maxX = window.innerWidth - rect.width - 8;
  const maxY = window.innerHeight - rect.height - 8;
  menu.style.left = `${Math.max(8, Math.min(clientX, maxX))}px`;
  menu.style.top = `${Math.max(8, Math.min(clientY, maxY))}px`;
  menu.style.visibility = '';
}

function dashAppendChartContextMenuItem(menu, { label, checked = false, disabled = false, onSelect }) {
  const btn = document.createElement('button');
  btn.type = 'button';
  btn.className = 'plan-row-context-menu-item';
  btn.disabled = disabled;
  btn.setAttribute('role', 'menuitem');
  const mark = checked ? '✓' : '';
  btn.innerHTML =
    `<span class="plan-row-context-menu-check" aria-hidden="true">${mark}</span>`
    + `<span class="plan-row-context-menu-label">${dashEscapeHtml(label)}</span>`;
  if (!disabled && onSelect) {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      onSelect();
      dashCloseChartContextMenu();
    });
  }
  menu.appendChild(btn);
  return btn;
}

function dashShowChartSeriesContextMenu(clientX, clientY, {
  title,
  isSolo = false,
  isShowAll = false,
  canHide = true,
  onSolo,
  onShowAll,
  onHide,
}) {
  dashCloseChartContextMenu();
  const menu = document.createElement('div');
  menu.className = 'plan-row-context-menu';
  menu.setAttribute('role', 'menu');

  const titleEl = document.createElement('div');
  titleEl.className = 'plan-row-context-menu-title';
  titleEl.textContent = title;
  menu.appendChild(titleEl);

  dashAppendChartContextMenuItem(menu, {
    label: '単体表示',
    checked: isSolo,
    onSelect: onSolo,
  });
  dashAppendChartContextMenuItem(menu, {
    label: '非表示',
    disabled: !canHide,
    onSelect: onHide,
  });

  const sep = document.createElement('div');
  sep.className = 'plan-row-context-menu-sep';
  menu.appendChild(sep);

  dashAppendChartContextMenuItem(menu, {
    label: '全てを表示',
    checked: isShowAll,
    onSelect: onShowAll,
  });

  dashPositionContextMenu(menu, clientX, clientY);
  dashChartContextMenuEl = menu;

  const onDismiss = () => dashCloseChartContextMenu();
  const controller = new AbortController();
  const { signal } = controller;
  dashChartContextMenuCleanup = () => controller.abort();

  document.addEventListener('pointerdown', (e) => {
    if (!menu.contains(e.target)) onDismiss();
  }, { signal, capture: true });
  window.addEventListener('scroll', onDismiss, { signal, capture: true });
  window.addEventListener('resize', onDismiss, { signal });
  window.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') onDismiss();
  }, { signal });
}

function dashOpenSeriesVisibilityContextMenu(clientX, clientY, {
  title,
  key,
  checkedKeys,
  itemKeys,
  onSolo,
  onShowAll,
  onHide,
}) {
  if (!onSolo || !onShowAll || !onHide || !checkedKeys || !key) return false;
  dashShowChartSeriesContextMenu(clientX, clientY, {
    title,
    isSolo: dashIsSoloCheckedKeys(checkedKeys, itemKeys, key),
    isShowAll: itemKeys.length > 0 && itemKeys.every((k) => checkedKeys.has(k)),
    canHide: checkedKeys.has(key),
    onSolo: () => onSolo(key),
    onShowAll,
    onHide: () => onHide(key),
  });
  return true;
}


function dashApplySectionFilterChartTitleStyle(titleEl, sectionFilterId) {
  const getColors = dashboardMountCtx?.getSectionFilterColors;
  if (!titleEl || !getColors || !sectionFilterId) return;
  const { background, color } = getColors(sectionFilterId);
  titleEl.style.setProperty('--dashboard-chart-title-bg', background);
  titleEl.style.color = color;
}

function dashGetSidebarHeaderColors(side) {
  const defaults = DASH_SIDEBAR_HEADER_COLOR_DEFAULTS[side];
  if (!defaults) return { background: '#888888', color: '#ffffff' };
  const root = document.querySelector('.plan-app');
  if (!root) return defaults;
  const styles = getComputedStyle(root);
  const bgVar = side === 'revenue' ? '--dashboard-revenue-color' : '--dashboard-expense-color';
  const textVar = side === 'revenue' ? '--dashboard-revenue-text-color' : '--dashboard-expense-text-color';
  return {
    background: styles.getPropertyValue(bgVar).trim() || defaults.background,
    color: styles.getPropertyValue(textVar).trim() || defaults.color,
  };
}

function dashNextGradId(prefix) {
  dashGradientSeq += 1;
  return `dash-${prefix}-${dashGradientSeq}`;
}

function dashFindSection(sections, id) {
  return sections?.find((s) => s.id === id) ?? null;
}

function dashFindRow(section, rowId) {
  return section?.rows?.find((r) => r.id === rowId) ?? null;
}

function dashItemKey(sectionId, row) {
  return `${sectionId}:${row.id}`;
}

function dashDisplayName(row) {
  const sub = String(row.subLabel ?? '').trim();
  if (sub && sub !== DASHBOARD_HOJO_NASHI) return sub;
  return String(row.label ?? '').trim();
}

function dashDisplayNameForBreakdown(row, breakdownMode) {
  const account = dashAccountLabel(row);
  const sub = String(row.subLabel ?? '').trim();
  const hasSub = sub && sub !== DASHBOARD_HOJO_NASHI;
  if (breakdownMode === 'sub' && hasSub) {
    return `${account} - ${sub}`;
  }
  return dashDisplayName(row);
}

function dashAccountLabel(row) {
  return String(row.label ?? '').trim();
}

function dashAccountGroupKey(sectionId, accountLabel) {
  return `${sectionId}|account|${accountLabel}`;
}

function dashAddRowValues(target, source) {
  for (const m of _dashFiscalMonths) {
    target[m] = (target[m] ?? 0) + (source[m] ?? 0);
  }
}

function dashFinalizeRowValues(values) {
  const total = _dashFiscalMonths.reduce((s, m) => s + (values[m] ?? 0), 0);
  values[DASHBOARD_GOUKEI] = total;
  return total;
}

function dashPushBreakdownItem(items, sectionId, row, breakdownMode = 'account') {
  const total = row.values?.[DASHBOARD_GOUKEI] ?? 0;
  if (total === 0) return;
  items.push({
    key: dashItemKey(sectionId, row),
    sectionId,
    accountLabel: dashAccountLabel(row),
    row,
    name: dashDisplayNameForBreakdown(row, breakdownMode),
    total,
    values: { ...(row.values ?? {}) },
  });
}

function dashIsAggregatingParentItem(section, row) {
  if (row.type !== 'item') return false;
  if (dashNormalizeSubLabel(row.subLabel) !== '') return false;
  const account = dashAccountLabel(row);
  return section.rows.some((r) =>
    r.type === 'sub'
    && dashAccountLabel(r) === account
    && dashNormalizeSubLabel(r.subLabel) !== ''
    && (r.values?.[DASHBOARD_GOUKEI] ?? 0) !== 0
  );
}

function dashIsBreakdownSubRow(section, sectionId, row) {
  if (row.type === 'sub') return true;
  if (row.type === 'item') {
    if (dashIsAggregatingParentItem(section, row)) return false;
    return true;
  }
  if (row.type === 'plan') return dashIsOrphanPlanRow(section, sectionId, row);
  return false;
}

function dashNormalizeSubLabel(sub) {
  const s = String(sub ?? '').trim();
  if (!s || s === DASHBOARD_HOJO_NASHI) return '';
  return s;
}

function dashRowLabelKey(row) {
  return `${dashAccountLabel(row)}\0${dashNormalizeSubLabel(row.subLabel)}`;
}

function dashIsOrphanPlanRow(section, sectionId, row) {
  if (row.type !== 'plan') return false;
  if ((row.values?.[DASHBOARD_GOUKEI] ?? 0) === 0) return false;

  const rowKey = dashRowLabelKey(row);
  if (section.rows.some((r) =>
    (r.type === 'item' || r.type === 'sub')
    && dashRowLabelKey(r) === rowKey
    && (r.values?.[DASHBOARD_GOUKEI] ?? 0) !== 0
  )) {
    return false;
  }

  // 人件費: 計画行は item/group 行へ合算済み（給料手当の二重計上防止）
  if (sectionId === 'personnel') {
    const account = dashAccountLabel(row);
    if (section.rows.some((r) =>
      (r.type === 'item' || r.type === 'group')
      && dashAccountLabel(r) === account
      && (r.values?.[DASHBOARD_GOUKEI] ?? 0) !== 0
    )) {
      return false;
    }
  }

  return true;
}

function dashIsBreakdownAccountRow(section, sectionId, row) {
  if (row.type === 'item' || row.type === 'group') return true;
  if (row.type === 'plan') return dashIsOrphanPlanRow(section, sectionId, row);
  return false;
}

function dashCollectBreakdownItemsBySub(sections, sectionIds) {
  const items = [];
  for (const sectionId of sectionIds) {
    const section = dashFindSection(sections, sectionId);
    if (!section?.rows) continue;
    for (const row of section.rows) {
      if (!dashIsBreakdownSubRow(section, sectionId, row)) continue;
      dashPushBreakdownItem(items, sectionId, row, 'sub');
    }
  }
  items.sort((a, b) => b.total - a.total);
  return items;
}

function dashCollectBreakdownItemsByAccount(sections, sectionIds) {
  const byKey = new Map();
  for (const sectionId of sectionIds) {
    const section = dashFindSection(sections, sectionId);
    if (!section?.rows) continue;
    for (const row of section.rows) {
      if (row.type === 'sub') continue;
      if (!dashIsBreakdownAccountRow(section, sectionId, row)) continue;
      const total = row.values?.[DASHBOARD_GOUKEI] ?? 0;
      if (total === 0) continue;
      const accountLabel = dashAccountLabel(row);
      if (!accountLabel) continue;
      const key = dashAccountGroupKey(sectionId, accountLabel);
      let item = byKey.get(key);
      if (!item) {
        item = {
          key,
          sectionId,
          accountLabel,
          name: accountLabel,
          total: 0,
          values: {},
        };
        byKey.set(key, item);
      }
      dashAddRowValues(item.values, row.values ?? {});
      item.total = dashFinalizeRowValues(item.values);
    }
  }
  return [...byKey.values()].sort((a, b) => b.total - a.total);
}

function dashCollectBreakdownItems(sections, sectionIds, mode = 'account') {
  return mode === 'sub'
    ? dashCollectBreakdownItemsBySub(sections, sectionIds)
    : dashCollectBreakdownItemsByAccount(sections, sectionIds);
}

/** 全期モード: 期をまたいで安定な内訳キー（行 id は期ごとに変わるため科目＋補助科目で合成） */
function dashAllPeriodItemKey(item, mode) {
  if (mode === 'account') return item.key;
  const sub = dashNormalizeSubLabel(item.row?.subLabel);
  // HTML data-* に載せるため NUL は使わない（属性値が途中で切れてチェック同期が壊れる）
  return `${item.sectionId}|all-sub|${item.accountLabel}|#sub#|${sub}`;
}

/** 全期モード: 全期分の内訳を合算し、全期連結の月次系列（seriesValues）を付与する */
function dashCollectAllPeriodBreakdownItems(allPeriods, sectionIds, mode) {
  const monthsPerPeriod = _dashDisplayMonths.length;
  const totalMonths = allPeriods.length * monthsPerPeriod;
  const byKey = new Map();
  allPeriods.forEach(({ data }, periodIndex) => {
    const items = dashCollectBreakdownItems(data?.sections ?? [], sectionIds, mode);
    for (const item of items) {
      const key = dashAllPeriodItemKey(item, mode);
      let merged = byKey.get(key);
      if (!merged) {
        merged = {
          ...item,
          key,
          total: 0,
          values: {},
          seriesValues: new Array(totalMonths).fill(0),
        };
        byKey.set(key, merged);
      }
      // 表示名・行参照は新しい期のものを優先する
      merged.name = item.name;
      merged.row = item.row;
      dashAddRowValues(merged.values, item.values ?? {});
      merged.total += item.total;
      _dashDisplayMonths.forEach((month, mi) => {
        merged.seriesValues[periodIndex * monthsPerPeriod + mi] += item.values?.[month] ?? 0;
      });
    }
  });
  const mergedItems = [...byKey.values()];
  for (const item of mergedItems) dashFinalizeRowValues(item.values);
  mergedItems.sort((a, b) => b.total - a.total);
  return mergedItems;
}

function dashSortBreakdownItems(items, sortMode = 'amount') {
  const sorted = [...items];
  if (sortMode === 'name') {
    sorted.sort((a, b) => a.name.localeCompare(b.name, 'ja'));
  } else {
    sorted.sort((a, b) => b.total - a.total);
  }
  return sorted;
}

function dashRemapCheckedKeys(checkedKeys, prevItems, nextItems, prevMode, nextMode) {
  if (prevMode === nextMode) return checkedKeys;
  const nextKeys = new Set();
  if (nextMode === 'account') {
    for (const item of nextItems) {
      const checked = prevItems.some((p) =>
        p.sectionId === item.sectionId
        && p.accountLabel === item.accountLabel
        && checkedKeys.has(p.key),
      );
      if (checked) nextKeys.add(item.key);
    }
  } else {
    for (const item of nextItems) {
      const accountKey = dashAccountGroupKey(item.sectionId, item.accountLabel);
      if (checkedKeys.has(accountKey)) nextKeys.add(item.key);
    }
  }
  return nextKeys;
}

function dashRemapSideCheckedKeys(checkedKeys, prevSideItems, nextSideItems, prevMode, nextMode) {
  const prevSideKeySet = new Set(prevSideItems.map((i) => i.key));
  const otherChecked = [...checkedKeys].filter((k) => !prevSideKeySet.has(k));
  const sideChecked = new Set([...checkedKeys].filter((k) => prevSideKeySet.has(k)));
  const remapped = dashRemapCheckedKeys(sideChecked, prevSideItems, nextSideItems, prevMode, nextMode);
  return new Set([...otherChecked, ...remapped]);
}

function dashFormatMonthAxisLabel(month, monthYearMap) {
  const year = monthYearMap[month];
  if (year == null) return month;
  const re = new RegExp('^(\\d{1,2})' + DASHBOARD_TSUKI + '$');
  const m = month.match(re);
  if (!m) return month;
  return `${year}${DASHBOARD_NEN}${m[1]}${DASHBOARD_TSUKI}`;
}

function dashLoadCheckedKeys(period, allKeys) {
  try {
    const raw = localStorage.getItem(DASHBOARD_CHECK_STORAGE_KEY);
    if (!raw) return new Set(allKeys);
    const parsed = JSON.parse(raw);
    const saved = parsed?.[period];
    if (!Array.isArray(saved)) return new Set(allKeys);
    return new Set(saved.filter((k) => allKeys.includes(k)));
  } catch {
    return new Set(allKeys);
  }
}

function dashClearCheckedKeys(period) {
  try {
    const raw = localStorage.getItem(DASHBOARD_CHECK_STORAGE_KEY);
    if (!raw) return;
    const parsed = JSON.parse(raw);
    if (!parsed?.[period]) return;
    delete parsed[period];
    localStorage.setItem(DASHBOARD_CHECK_STORAGE_KEY, JSON.stringify(parsed));
  } catch {
    /* ignore */
  }
}
function dashSaveCheckedKeys(period, checkedKeys) {
  try {
    const raw = localStorage.getItem(DASHBOARD_CHECK_STORAGE_KEY);
    const parsed = raw ? JSON.parse(raw) : {};
    parsed[period] = [...checkedKeys];
    localStorage.setItem(DASHBOARD_CHECK_STORAGE_KEY, JSON.stringify(parsed));
  } catch {
    /* ignore */
  }
}

function dashIsSoloCheckedKeys(checkedKeys, itemKeys, key) {
  return itemKeys.every((k) => checkedKeys.has(k) === (k === key));
}

function dashIsSideFullyChecked(checkedKeys, items) {
  if (!items.length) return true;
  return items.every((item) => checkedKeys.has(item.key));
}

function dashRemapPeriodSideCheckedKeys(checkedKeys, prevItems, nextItems, checkAll, prevMode, nextMode) {
  const prevSideKeySet = new Set(prevItems.map((i) => i.key));
  const otherChecked = [...checkedKeys].filter((k) => !prevSideKeySet.has(k));
  let sideChecked;
  if (checkAll) {
    sideChecked = nextItems.map((i) => i.key);
  } else {
    const prevSideChecked = new Set([...checkedKeys].filter((k) => prevSideKeySet.has(k)));
    sideChecked = [...dashRemapCheckedKeys(prevSideChecked, prevItems, nextItems, prevMode, nextMode)];
  }
  return new Set([...otherChecked, ...sideChecked]);
}

function dashSyncSideCheckAllFlags(state, revenueItems, expenseItems) {
  state.revenueCheckAll = dashIsSideFullyChecked(state.checkedKeys, revenueItems);
  state.expenseCheckAll = dashIsSideFullyChecked(state.checkedKeys, expenseItems);
}

function dashSumCheckedMonthly(items, checkedKeys, month) {
  let total = 0;
  for (const item of items) {
    if (!checkedKeys.has(item.key)) continue;
    total += item.values[month] ?? 0;
  }
  return total;
}

function dashColorForItemIndex(index) {
  return DASH_ITEM_COLORS[index % DASH_ITEM_COLORS.length];
}

function dashBuildItemColorMap(items) {
  const map = new Map();
  items.forEach((item, index) => {
    map.set(item.key, dashColorForItemIndex(index));
  });
  return map;
}

function dashBuildStackedSeries(items, checkedKeys, colorMap) {
  return items
    .filter((item) => checkedKeys.has(item.key))
    .map((item) => ({
      key: item.key,
      label: item.name,
      color: colorMap.get(item.key) ?? DASH_COLOR_BAR,
      // 全期モードでは全期連結の系列（seriesValues）を使う
      values: item.seriesValues
        ? item.seriesValues.map((v) => Math.abs(v))
        : _dashDisplayMonths.map((month) => Math.abs(item.values[month] ?? 0)),
    }));
}

function dashEscapeHtml(text) {
  return String(text ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function dashEscapeSeriesKeyForSelector(seriesKey) {
  return typeof CSS !== 'undefined' && CSS.escape
    ? CSS.escape(seriesKey)
    : String(seriesKey).replace(/["\\]/g, '\\$&');
}

function dashResolveDrilldownTarget(sections, item) {
  const section = dashFindSection(sections, item.sectionId);
  if (!section) return null;
  if (item.row) {
    return { section, row: item.row };
  }
  return {
    section,
    row: { type: 'group', label: item.accountLabel, id: item.key },
  };
}

function dashGetDrilldownCtx(ctx) {
  const { data, showJournalPopup, hasJournalDrilldown } = ctx;
  // 全期モードでは仕訳が選択期分しか読み込まれていないためドリルダウンを無効化する
  if (ctx.allPeriods) return null;
  if (!showJournalPopup || !hasJournalDrilldown) return null;
  return {
    sections: data?.sections ?? [],
    showJournalPopup,
    hasJournalDrilldown,
  };
}

function dashCanShowJournal(drilldownCtx, item, month) {
  if (!drilldownCtx || !item) return false;
  const target = dashResolveDrilldownTarget(drilldownCtx.sections, item);
  if (!target) return false;
  return drilldownCtx.hasJournalDrilldown(target.section, target.row, month);
}

function dashShowJournal(drilldownCtx, item, month) {
  if (!dashCanShowJournal(drilldownCtx, item, month)) return;
  const target = dashResolveDrilldownTarget(drilldownCtx.sections, item);
  if (!target) return;
  drilldownCtx.showJournalPopup(target.section, target.row, month);
}

function dashCanShowCfJournal(drilldownCtx, cfSectionId, rowId, month) {
  if (!drilldownCtx) return false;
  const section = dashFindSection(drilldownCtx.sections, cfSectionId);
  const row = dashFindRow(section, rowId);
  if (!section || !row) return false;
  return drilldownCtx.hasJournalDrilldown(section, row, month);
}

function dashShowCfJournal(drilldownCtx, cfSectionId, rowId, month) {
  if (!dashCanShowCfJournal(drilldownCtx, cfSectionId, rowId, month)) return;
  const section = dashFindSection(drilldownCtx.sections, cfSectionId);
  const row = dashFindRow(section, rowId);
  drilldownCtx.showJournalPopup(section, row, month);
}

function dashResolveStackedChartDrilldown(hoverRect, ev, svg, itemByKey, drilldownCtx, hitCtx = null) {
  if (!drilldownCtx) return null;
  let monthIdx;
  let seriesKey;
  if (hitCtx?.series && hitCtx?.labels && hitCtx?.xScale && hitCtx?.yScale) {
    const hit = dashHitTestStackedBar(
      hitCtx.series,
      hitCtx.labels,
      hitCtx.xScale,
      hitCtx.yScale,
      svg,
      ev.clientX,
      ev.clientY,
      hitCtx.layout,
    );
    if (!hit) return null;
    monthIdx = hit.monthIdx;
    seriesKey = hit.key;
  } else {
    const seg = dashPeekChartElementUnder(hoverRect, ev.clientX, ev.clientY, '.dashboard-chart-segment');
    if (!seg || seg.closest('svg') !== svg) return null;
    monthIdx = Number(seg.getAttribute('data-month-index'));
    seriesKey = seg.getAttribute('data-series-key');
  }
  // 全期連結インデックスは単期の月配列に収まらないため、単期ドリルダウン時のみ月名を解決する
  const month = _dashDisplayMonths[monthIdx];
  if (!month) return null;
  const item = itemByKey.get(seriesKey);
  if (!dashCanShowJournal(drilldownCtx, item, month)) return null;
  return { item, month };
}

function dashResolveGroupedChartDrilldown(hoverRect, ev, svg, drilldownCtx) {
  if (!drilldownCtx) return null;
  const cfTargets = [
    { sectionId: 'cfIn', rowId: 'cf-in', seriesIndex: 0 },
    { sectionId: 'cfOut', rowId: 'cf-out', seriesIndex: 1 },
  ];
  const bar = dashPeekChartElementUnder(hoverRect, ev.clientX, ev.clientY, '.dashboard-chart-bar');
  if (!bar || bar.closest('svg') !== svg) return null;
  const monthIdx = Number(bar.getAttribute('data-month-index'));
  const seriesIndex = Number(bar.getAttribute('data-series-index'));
  const month = _dashDisplayMonths[monthIdx];
  const cf = cfTargets.find((target) => target.seriesIndex === seriesIndex);
  if (!cf || !dashCanShowCfJournal(drilldownCtx, cf.sectionId, cf.rowId, month)) return null;
  return { cfSectionId: cf.sectionId, cfRowId: cf.rowId, month };
}

const DASH_CHART_OUTLINE_FADE_MS = 360;

function dashClearChartHighlightOutlines(wrap, { immediate = false } = {}) {
  if (!wrap) return;
  wrap.querySelectorAll('.dashboard-chart-highlight-layer').forEach((layer) => {
    if (immediate) {
      layer.replaceChildren();
      return;
    }
    const outlines = [...layer.querySelectorAll('.dashboard-chart-segment-outline:not(.is-fading-out)')];
    if (outlines.length === 0) return;
    for (const outline of outlines) {
      outline.classList.add('is-fading-out');
      const remove = () => {
        if (outline.isConnected) outline.remove();
      };
      outline.addEventListener('transitionend', (ev) => {
        if (ev.propertyName === 'opacity') remove();
      }, { once: true });
      setTimeout(remove, DASH_CHART_OUTLINE_FADE_MS + 50);
    }
  });
}

function dashAppendSegmentOutline(layer, seg, { stroke = null, strokeWidth = 1, expand = false, outlineClass = 'dashboard-chart-segment-outline' } = {}) {
  const x = Number(seg.getAttribute('x') ?? 0);
  const y = Number(seg.getAttribute('y') ?? 0);
  const w = Number(seg.getAttribute('width') ?? 0);
  const h = Number(seg.getAttribute('height') ?? 0);
  if (w <= 0 || h <= 0) return;
  const pad = expand ? strokeWidth / 2 : 0;
  const outline = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
  outline.setAttribute('class', outlineClass);
  outline.setAttribute('x', String(x - pad));
  outline.setAttribute('y', String(y - pad));
  outline.setAttribute('width', String(w + pad * 2));
  outline.setAttribute('height', String(h + pad * 2));
  outline.setAttribute('rx', seg.getAttribute('rx') || '1');
  outline.setAttribute('fill', 'none');
  if (stroke) outline.setAttribute('stroke', stroke);
  outline.setAttribute('stroke-width', String(strokeWidth));
  outline.setAttribute('pointer-events', 'none');
  layer.appendChild(outline);
}

/** data-series-key 照合（CSS.escape を属性セレクタに使うとキー文字で外れることがある） */
function dashElementsBySeriesKey(root, selector, seriesKey) {
  if (!root || seriesKey == null || seriesKey === '') return [];
  return [...root.querySelectorAll(selector)].filter(
    (el) => el.getAttribute('data-series-key') === seriesKey,
  );
}

function dashSyncChartHighlightOutlines(wrap, seriesKey, { focusMonthIndex = null } = {}) {
  dashClearChartHighlightOutlines(wrap, { immediate: true });
  if (!wrap || !seriesKey) return;
  dashElementsBySeriesKey(wrap, '.dashboard-chart-segment[data-series-key]', seriesKey).forEach((seg) => {
    const layer = seg.ownerSVGElement?.querySelector('.dashboard-chart-highlight-layer');
    if (!layer) return;
    const monthIdx = Number(seg.getAttribute('data-month-index'));
    dashAppendSegmentOutline(layer, seg);
    if (focusMonthIndex != null && monthIdx === focusMonthIndex) {
      dashAppendSegmentOutline(layer, seg, {
        outlineClass: 'dashboard-chart-segment-outline dashboard-chart-segment-outline--focus',
      });
    }
  });
}

function dashSetSeriesHighlight(wrap, seriesKey, active, sidebarRoot = null, {
  scrollSidebar = false,
  focusMonthIndex = null,
} = {}) {
  if (!wrap) return;
  if (active && seriesKey) {
    dashSyncChartHighlightOutlines(wrap, seriesKey, { focusMonthIndex });
  } else {
    dashClearChartHighlightOutlines(wrap);
  }
  if (!seriesKey) return;
  dashElementsBySeriesKey(wrap, '.dashboard-chart-legend-chip[data-series-key]', seriesKey).forEach((el) => {
    el.classList.toggle('is-highlighted', active);
  });
  if (sidebarRoot) {
    dashElementsBySeriesKey(sidebarRoot, '.dashboard-sidebar-row[data-series-key]', seriesKey).forEach((el) => {
      el.classList.toggle('is-series-highlighted', active);
      if (active && scrollSidebar) el.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
    });
    dashElementsBySeriesKey(sidebarRoot, '.dashboard-sidebar-pie-slice-group[data-series-key]', seriesKey).forEach((el) => {
      el.classList.toggle('is-series-highlighted', active);
    });
    sidebarRoot.querySelector('.dashboard-sidebar-pie-wrap')
      ?.classList.toggle('is-highlight-active', active);
  }
}

/**
 * リスト→棒グラフのハイライトをイベント委譲で結ぶ。
 * preserveSidebars 後も、常に現在の wrap / chartMode を見る。
 */
function dashBindSidebarListSeriesHighlight(sidebarEl, side) {
  if (!sidebarEl) return;
  const list = sidebarEl.querySelector('.dashboard-sidebar-list');
  if (!list) return;

  list._dashHighlightAbort?.abort();
  const ac = new AbortController();
  list._dashHighlightAbort = ac;
  const { signal } = ac;
  let activeKey = null;

  const clearActive = () => {
    if (!activeKey) return;
    const wrap = sidebarEl.closest('.dashboard-wrap');
    if (wrap) dashSetSeriesHighlight(wrap, activeKey, false, sidebarEl);
    activeKey = null;
  };

  const setActive = (key) => {
    if (!key || key === activeKey) return;
    const wrap = sidebarEl.closest('.dashboard-wrap');
    const ctx = dashboardMountCtx;
    if (!wrap || !ctx || ctx.state.chartMode !== side) {
      clearActive();
      return;
    }
    if (activeKey) dashSetSeriesHighlight(wrap, activeKey, false, sidebarEl);
    activeKey = key;
    dashSetSeriesHighlight(wrap, key, true, sidebarEl);
  };

  list.addEventListener('mousemove', (ev) => {
    const row = ev.target instanceof Element
      ? ev.target.closest('.dashboard-sidebar-row[data-series-key]')
      : null;
    if (!row || !list.contains(row)) {
      clearActive();
      return;
    }
    setActive(row.getAttribute('data-series-key'));
  }, { signal });

  list.addEventListener('mouseleave', () => {
    clearActive();
  }, { signal });

  // 棒グラフ再描画直後にカーソルがリスト上でも、動かさずハイライトできるよう復元する
  requestAnimationFrame(() => {
    if (!list.isConnected || !list.matches(':hover')) return;
    const hovered = list.querySelector('.dashboard-sidebar-row[data-series-key]:hover');
    const key = hovered?.getAttribute('data-series-key');
    if (key) setActive(key);
  });
}

function dashBindChartSeriesHover(chartContainer, highlightWrap, sidebarRoot, {
  checkedKeys = null,
  itemKeys = [],
  breakdownItems = [],
  onSolo = null,
  onShowAll = null,
  onHide = null,
} = {}) {
  if (!chartContainer) return;
  const itemByKey = new Map(breakdownItems.map((item) => [item.key, item]));
  const canHighlight = Boolean(highlightWrap && sidebarRoot);
  const canMenu = Boolean(onSolo && onShowAll && onHide && checkedKeys);
  chartContainer.querySelectorAll('.dashboard-chart-legend-chip[data-series-key]').forEach((el) => {
    const key = el.getAttribute('data-series-key');
    if (!key) return;
    if (canHighlight) {
      el.addEventListener('mouseenter', () => dashSetSeriesHighlight(highlightWrap, key, true, sidebarRoot, {
        scrollSidebar: true,
      }));
      el.addEventListener('mouseleave', () => dashSetSeriesHighlight(highlightWrap, key, false, sidebarRoot));
    }
    if (canMenu) {
      el.addEventListener('contextmenu', (ev) => {
        const item = itemByKey.get(key);
        const title = item?.name ?? ((el.textContent || '').trim() || key);
        ev.preventDefault();
        dashOpenSeriesVisibilityContextMenu(ev.clientX, ev.clientY, {
          title,
          key,
          checkedKeys,
          itemKeys,
          onSolo,
          onShowAll,
          onHide,
        });
      });
    }
  });
}

function dashRenderStackedLegendHtml(series) {
  if (!series.length) return '';
  return series.map((s) =>
    `<span class="dashboard-chart-legend-chip" data-series-key="${dashEscapeHtml(s.key)}"><span class="dashboard-chart-legend-swatch" style="background:${s.color}"></span>${dashEscapeHtml(s.label)}</span>`,
  ).join('');
}

function dashBuildMonthlySeries(data, appSettings) {
  const sections = data?.sections ?? [];
  const monthYearMap = buildMonthYearMap(
    appSettings.businessStartYear,
    appSettings.fiscalPeriod,
    dashGetFiscalEndMonth(data),
  );
  const cfIn = dashFindRow(dashFindSection(sections, 'cfIn'), 'cf-in')?.values ?? {};
  const cfOut = dashFindRow(dashFindSection(sections, 'cfOut'), 'cf-out')?.values ?? {};
  const profitSection = dashFindSection(sections, 'profit');
  const ordProfit = profitSection?.rows?.find((r) => r.id === 'ord-profit')?.values ?? {};
  const cashSection = dashFindSection(sections, 'cashBalance');
  const cashRow = cashSection?.rows?.find(
    (r) => r.type === 'total' || String(r.label ?? '').includes(DASHBOARD_GENKIN_TOTAL),
  );
  const cashValues = cashRow?.values ?? {};

  return _dashDisplayMonths.map((month) => ({
    month,
    label: dashFormatMonthAxisLabel(month, monthYearMap),
    inflow: Math.abs(cfIn[month] ?? 0),
    outflow: Math.abs(cfOut[month] ?? 0),
    profit: ordProfit[month] ?? 0,
    cash: cashValues[month] ?? 0,
  }));
}

/** 全期モード: 各期の月次系列を期の昇順に連結する */
function dashBuildMonthlySeriesAllPeriods(allPeriods, appSettings) {
  const result = [];
  for (const { fiscalPeriod, data } of allPeriods) {
    result.push(...dashBuildMonthlySeries(data, { ...appSettings, fiscalPeriod }));
  }
  return result;
}

function dashSplitMonthLabel(fullLabel) {
  const re = new RegExp('^(\\d{4})' + DASHBOARD_NEN + '(\\d{1,2})' + DASHBOARD_TSUKI + '$');
  const m = String(fullLabel ?? '').match(re);
  if (!m) return { year: '', month: fullLabel };
  return { year: `${m[1]}${DASHBOARD_NEN}`, month: `${m[2]}${DASHBOARD_TSUKI}` };
}

function dashNiceStepCandidates(roughStep) {
  const mag = 10 ** Math.floor(Math.log10(Math.abs(roughStep) || 1));
  const finer = mag / 10;
  const multiples = [1, 1.5, 2, 2.5, 5, 10];
  const candidates = new Set();
  for (const base of [finer, mag, mag * 10]) {
    for (const f of multiples) {
      candidates.add(f * base);
    }
  }
  return [...candidates].filter((s) => s > 0).sort((a, b) => a - b);
}

function dashPickStepForSpan(span, targetTicks = 6) {
  const safeSpan = Math.max(span, 1);
  const roughStep = safeSpan / Math.max(1, targetTicks - 1);
  const candidates = dashNiceStepCandidates(roughStep);
  let best = null;
  let bestScore = Infinity;
  for (const step of candidates) {
    const count = Math.floor(safeSpan / step) + 1;
    if (count < 3 || count > 10) continue;
    const score = Math.abs(count - targetTicks) + Math.max(0, count - 8) * 0.35;
    if (score < bestScore) {
      bestScore = score;
      best = step;
    }
  }
  if (best == null) {
    best = candidates.find((step) => {
      const count = Math.floor(safeSpan / step) + 1;
      return count >= 3 && count <= 10;
    }) ?? candidates[Math.max(0, Math.floor(candidates.length / 2))] ?? 1;
  }
  return best;
}

function dashComputeYAxisScale(dataMin, dataMax, { clampMinZero = false, includeZero = false, targetTicks = 6 } = {}) {
  let min = Number.isFinite(dataMin) ? dataMin : 0;
  let max = Number.isFinite(dataMax) ? dataMax : 1;
  if (clampMinZero) min = 0;
  if (includeZero) {
    min = Math.min(min, 0);
    max = Math.max(max, 0);
  }
  if (min === max) {
    if (max <= 0) {
      min = max - 1;
      max = 0;
    } else {
      min = clampMinZero ? 0 : min;
      max = max || 1;
    }
  }

  let scaleMin = clampMinZero ? 0 : min;
  let scaleMax = max;
  const dataSpan = Math.max(scaleMax - scaleMin, 1);
  const step = dashPickStepForSpan(dataSpan, targetTicks);

  const tickStart = clampMinZero ? 0 : Math.floor(scaleMin / step) * step;
  const tickEnd = Math.ceil(scaleMax / step) * step;
  scaleMin = clampMinZero ? 0 : tickStart;
  scaleMax = tickEnd;

  const ticks = [];
  for (let t = tickStart; t <= scaleMax + step * 1e-9; t += step) {
    if (t >= scaleMin - step * 1e-9) ticks.push(t);
  }
  if (ticks.length === 0) ticks.push(scaleMin);
  if (includeZero && scaleMin < 0 && scaleMax > 0 && !ticks.some((t) => Math.abs(t) < step * 1e-9)) {
    ticks.push(0);
    ticks.sort((a, b) => a - b);
  }

  const span = scaleMax - scaleMin || 1;
  return { min: scaleMin, max: scaleMax, ticks, span };
}

function dashMakeYScale(scale, pad, plotH) {
  return (v) => pad.top + plotH - ((v - scale.min) / scale.span) * plotH;
}

function dashRenderYAxisGrid(scale, yScale, pad, width, { negativeTicksRed = false } = {}) {
  let markup = '';
  for (const val of scale.ticks) {
    const y = yScale(val);
    markup += `<line x1="${pad.left}" y1="${y}" x2="${width - pad.right}" y2="${y}" class="dashboard-chart-grid"/>`;
    const negClass = negativeTicksRed && val < 0 ? ' dashboard-chart-axis-y--negative' : '';
    markup += `<text x="${pad.left - 8}" y="${y + 4}" class="dashboard-chart-axis-y${negClass}" text-anchor="end">${dashFormatAxisYen(val)}</text>`;
  }
  return markup;
}

/** メインチャート描画領域の初期推定高さ（px、viewport scale 適用前） */
const DASH_MAIN_CHART_BAR_HEIGHT = 326;
/** 下段（利益率・預金残高）チャートの初期推定高さ（px、viewport scale 適用前） */
const DASH_BOTTOM_CHART_HEIGHT = 230;

/** コンテナの内側幅（padding 除く）を px で測る。未接続時は fallback を返す */
function dashMeasureChartInnerWidth(container, fallback) {
  if (!container?.isConnected) return fallback;
  const style = window.getComputedStyle(container);
  const inner = container.clientWidth
    - (parseFloat(style.paddingLeft) || 0)
    - (parseFloat(style.paddingRight) || 0);
  return inner > 120 ? Math.round(inner) : fallback;
}

/**
 * チャートを 2 パスで描画する。まず推定高さで描き、CSS フレックスで確定した
 * 描画枠（wrapSelector）の実測高さと差があれば、その高さで描き直す。
 * これで枠いっぱいに SVG が広がり、余白も切れも出ない。
 */
function dashRenderWithMeasuredHeight(container, fallbackHeight, wrapSelector, renderFn) {
  const cached = Number(container.dataset?.dashChartHeight);
  const initial = Number.isFinite(cached) && cached > 40 ? cached : fallbackHeight;
  renderFn(initial);
  const wrap = container.querySelector(wrapSelector);
  const measured = wrap?.clientHeight ?? 0;
  if (measured > 40 && Math.abs(measured - initial) > 2) {
    renderFn(measured);
  }
  const finalHeight = measured > 40 ? measured : initial;
  if (container.dataset) container.dataset.dashChartHeight = String(finalHeight);
}

/** Y 軸目盛りラベルの最大長から左パディングを算出（余白の無駄と重なりを防ぐ） */
function dashComputeAxisLeftPad(ticks, viewportScale) {
  // plan.css の .dashboard-chart-axis-y の font-size（10px * scale）と揃える
  const fontPx = 10 * viewportScale;
  let maxUnits = 4;
  for (const t of ticks) {
    const text = dashFormatAxisYen(t);
    let units = 0;
    for (const ch of text) units += ch === DASHBOARD_YEN ? 1 : 0.62;
    maxUnits = Math.max(maxUnits, units);
  }
  return Math.ceil(maxUnits * fontPx + 16);
}

function dashChartLayout({ width, plotH = null, height = null, left = 112, right = 16, top = 28, hasLegend = false }) {
  const axisGap = 12;
  const monthRow = 11;
  const yearRow = 11;
  const rowGap = 6;
  const legendGap = 8;
  const legendRow = 14;
  const bottomPad = 8;
  const axisH = axisGap + monthRow + rowGap + yearRow;
  const legendH = hasLegend ? legendGap + legendRow : 0;
  const bottom = axisH + legendH + bottomPad;
  // height 指定時はプロット高を逆算して枠にぴったり収める
  const resolvedPlotH = plotH ?? Math.max(80, (height ?? 300) - top - bottom);
  const finalHeight = top + resolvedPlotH + bottom;
  const plotBottom = top + resolvedPlotH;
  const monthY = plotBottom + axisGap;
  const yearY = monthY + monthRow + rowGap;
  const legendY = yearY + yearRow + legendGap;
  return {
    width,
    height: finalHeight,
    pad: { top, right, bottom, left },
    plotW: width - left - right,
    plotH: resolvedPlotH,
    plotBottom,
    plotTop: top,
    monthY,
    yearY,
    legendY,
  };
}

function dashRenderPlotClip(layout, clipId) {
  const { pad, plotW, plotH } = layout;
  return `<clipPath id="${clipId}"><rect x="${pad.left}" y="${pad.top}" width="${plotW}" height="${plotH}"/></clipPath>`;
}

function dashRenderXAxisLabelsTwoRow(labels, xScale, layout, { stepPx = null } = {}) {
  const { monthY, yearY } = layout;
  // ラベル間隔が狭いときは間引いて重なりを防ぐ（"12月" ≒ 2.6em を目安にする）
  const viewportScale = getViewportScale();
  const minLabelW = 26 * viewportScale + 4;
  const skip = stepPx != null && stepPx > 0 ? Math.max(1, Math.ceil(minLabelW / stepPx)) : 1;
  // 年ラベル（例: 2025年）はおよそ 5 文字分の幅。前の年ラベルと重なる場合は右へずらす
  const yearLabelW = 50 * viewportScale;
  let markup = '';
  let prevYear = null;
  let prevYearRight = -Infinity;
  for (let i = 0; i < labels.length; i += 1) {
    if (i % skip !== 0) continue;
    const x = xScale(i);
    const { year, month } = dashSplitMonthLabel(labels[i]);
    markup += `<text x="${x}" y="${monthY}" class="dashboard-chart-axis-x" text-anchor="middle" dominant-baseline="hanging">${month}</text>`;
    if (year && year !== prevYear) {
      const yearX = Math.max(x, prevYearRight + yearLabelW / 2 + 4);
      markup += `<text x="${yearX}" y="${yearY}" class="dashboard-chart-axis-year" text-anchor="middle" dominant-baseline="hanging">${year}</text>`;
      prevYear = year;
      prevYearRight = yearX + yearLabelW / 2;
    }
  }
  return markup;
}

const DASH_CHART_DRAW_MS = 520;

function dashPlayChartDrawAnimation(container, { animate = false } = {}) {
  if (!animate) return;
  const wrap = container.querySelector('.dashboard-bar-chart-wrap, .dashboard-line-chart-wrap');
  if (wrap) {
    wrap.classList.remove('is-drawing');
    void wrap.offsetWidth;
    wrap.classList.add('is-drawing');
  }

  container.querySelectorAll('.dashboard-line-chart-current, .dashboard-line-chart-prev path, .dashboard-line-chart-prev-prev path').forEach((path) => {
    if (!(path instanceof SVGPathElement)) return;
    let len;
    try {
      len = path.getTotalLength();
    } catch {
      return;
    }
    if (!Number.isFinite(len) || len <= 0) return;
    path.style.setProperty('--dash-path-len', String(len));
    path.classList.remove('is-drawing');
    void path.getBoundingClientRect();
    path.classList.add('is-drawing');
  });

  const legend = container.querySelector('.dashboard-chart-legend-grid');
  if (legend) {
    legend.classList.remove('is-drawing');
    void legend.offsetWidth;
    legend.classList.add('is-drawing');
  }

  window.setTimeout(() => {
    wrap?.classList.remove('is-drawing');
    container.querySelectorAll('.dashboard-line-chart-current, .dashboard-line-chart-prev path, .dashboard-line-chart-prev-prev path').forEach((path) => {
      path.classList.remove('is-drawing');
      path.style.removeProperty('--dash-path-len');
    });
    legend?.classList.remove('is-drawing');
  }, DASH_CHART_DRAW_MS);
}

const DASH_SIDEBAR_BAR_DRAW_MS = 400;

function dashPlaySidebarBarDrawAnimation(container, { animate = false } = {}) {
  if (!animate) return;
  const list = container.querySelector('.dashboard-sidebar-list');
  if (!list) return;
  list.classList.remove('is-drawing');
  void list.offsetWidth;
  list.classList.add('is-drawing');
  window.setTimeout(() => list.classList.remove('is-drawing'), DASH_SIDEBAR_BAR_DRAW_MS);
}

const DASH_SIDEBAR_PIE_TOTAL_MS = 1000;
const DASH_SIDEBAR_PIE_SIZE = 320;
const DASH_SIDEBAR_PIE_OUTER_INSET = 8;
const DASH_SIDEBAR_PIE_RING_WIDTH = 78;

function dashEaseOutCubic(t) {
  const x = Math.min(1, Math.max(0, t));
  return 1 - (1 - x) ** 3;
}

function dashPiePrefersReducedMotion() {
  return typeof window !== 'undefined'
    && window.matchMedia('(prefers-reduced-motion: reduce)').matches;
}

function dashPolarToCartesian(cx, cy, r, angleDeg) {
  const rad = ((angleDeg - 90) * Math.PI) / 180;
  return { x: cx + r * Math.cos(rad), y: cy + r * Math.sin(rad) };
}

function dashDonutSlicePath(cx, cy, outerR, innerR, startAngle, endAngle) {
  const sweep = endAngle - startAngle;
  if (sweep <= 0) return '';
  if (sweep >= 359.999) {
    const mid = startAngle + 180;
    const oStart = dashPolarToCartesian(cx, cy, outerR, startAngle);
    const oMid = dashPolarToCartesian(cx, cy, outerR, mid);
    const oEnd = dashPolarToCartesian(cx, cy, outerR, endAngle);
    const iEnd = dashPolarToCartesian(cx, cy, innerR, endAngle);
    const iMid = dashPolarToCartesian(cx, cy, innerR, mid);
    const iStart = dashPolarToCartesian(cx, cy, innerR, startAngle);
    return `M ${oStart.x} ${oStart.y} A ${outerR} ${outerR} 0 1 1 ${oMid.x} ${oMid.y} A ${outerR} ${outerR} 0 1 1 ${oEnd.x} ${oEnd.y} L ${iEnd.x} ${iEnd.y} A ${innerR} ${innerR} 0 1 0 ${iMid.x} ${iMid.y} A ${innerR} ${innerR} 0 1 0 ${iStart.x} ${iStart.y} Z`;
  }
  const outerStart = dashPolarToCartesian(cx, cy, outerR, startAngle);
  const outerEnd = dashPolarToCartesian(cx, cy, outerR, endAngle);
  const innerEnd = dashPolarToCartesian(cx, cy, innerR, endAngle);
  const innerStart = dashPolarToCartesian(cx, cy, innerR, startAngle);
  const largeArc = sweep > 180 ? 1 : 0;
  return `M ${outerStart.x} ${outerStart.y} A ${outerR} ${outerR} 0 ${largeArc} 1 ${outerEnd.x} ${outerEnd.y} L ${innerEnd.x} ${innerEnd.y} A ${innerR} ${innerR} 0 ${largeArc} 0 ${innerStart.x} ${innerStart.y} Z`;
}

function dashPieSliceDisplayName(item) {
  const sub = dashNormalizeSubLabel(item.row?.subLabel);
  if (sub) return sub;
  const name = String(item.name ?? '').trim();
  const splitAt = name.indexOf(' - ');
  if (splitAt > 0) {
    const tail = name.slice(splitAt + 3).trim();
    if (tail) return tail;
  }
  return item.accountLabel || name;
}

function dashFormatPieSliceLabelLines(text, pct, sweep) {
  const pctText = `${pct.toFixed(2)}%`;
  if (sweep < 8) return [];
  if (sweep < 14) return [pctText];
  const name = String(text ?? '').trim();
  if (!name) return [pctText];
  const maxChars = Math.max(2, Math.floor(sweep / 4.5));
  const nameLine = name.length <= maxChars ? name : `${name.slice(0, maxChars - 1)}…`;
  return [nameLine, pctText];
}

function dashRenderPieSliceLabels(text, pct, sweep, cx, cy, outerR, innerR, midAngle) {
  const lines = dashFormatPieSliceLabelLines(text, pct, sweep);
  if (!lines.length) return '';
  const labelR = innerR + (outerR - innerR) * 0.58;
  const pos = dashPolarToCartesian(cx, cy, labelR, midAngle);
  const lineHeight = 12;
  const startY = pos.y - ((lines.length - 1) * lineHeight) / 2;
  return lines.map((line, index) => {
    const isPct = index === lines.length - 1 && lines.length > 1;
    const cls = isPct ? ' dashboard-sidebar-pie-label-pct' : '';
    return `<text class="dashboard-sidebar-pie-label${cls}" x="${pos.x}" y="${startY + index * lineHeight}" text-anchor="middle" dominant-baseline="middle">${dashEscapeHtml(line)}</text>`;
  }).join('');
}

function dashRenderPieCenterTitle(lines, cx, cy) {
  if (!lines?.length) return '';
  const lineHeight = 17;
  const startY = cy - ((lines.length - 1) * lineHeight) / 2;
  return `<g class="dashboard-sidebar-pie-center-label">${lines.map((line, index) =>
    `<text class="dashboard-sidebar-pie-center${index === 0 ? ' dashboard-sidebar-pie-center-main' : ' dashboard-sidebar-pie-center-sub'}" x="${cx}" y="${startY + index * lineHeight}" text-anchor="middle" dominant-baseline="middle">${dashEscapeHtml(line)}</text>`,
  ).join('')}</g>`;
}

function dashBuildPieChartSlices(items, checkedKeys, colorMap) {
  const filtered = items.filter((item) =>
    checkedKeys.has(item.key) && Math.abs(item.total) > 0);
  const total = filtered.reduce((sum, item) => sum + Math.abs(item.total), 0);
  if (total <= 0) return [];

  let angle = 0;
  return filtered.map((item, index) => {
    const value = Math.abs(item.total);
    const sweep = (value / total) * 360;
    const startAngle = angle;
    const endAngle = angle + sweep;
    angle = endAngle;
    return {
      key: item.key,
      name: item.name,
      pieLabel: dashPieSliceDisplayName(item),
      value,
      color: colorMap.get(item.key) ?? DASH_COLOR_BAR,
      startAngle,
      endAngle,
      pct: (value / total) * 100,
      index,
    };
  });
}

function dashFinishSidebarPieSlices(pieWrap, slices, cx, cy, outerR, innerR) {
  if (!pieWrap || !slices.length) return;
  pieWrap.querySelectorAll('.dashboard-sidebar-pie-slice-group').forEach((group, index) => {
    const slice = slices[index];
    if (!slice) return;
    const path = group.querySelector('.dashboard-sidebar-pie-slice');
    const labels = group.querySelectorAll('.dashboard-sidebar-pie-label');
    if (!path) return;
    const finalPath = dashDonutSlicePath(cx, cy, outerR, innerR, slice.startAngle, slice.endAngle);
    if (finalPath) path.setAttribute('d', finalPath);
    labels.forEach((label) => label.classList.add('is-visible'));
  });
}

function dashPlaySidebarPieSweepAnimation(pieWrap, slices, cx, cy, outerR, innerR, { animate = false } = {}) {
  if (!pieWrap || !slices.length) return;
  if (!animate || dashPiePrefersReducedMotion()) {
    dashFinishSidebarPieSlices(pieWrap, slices, cx, cy, outerR, innerR);
    return;
  }

  pieWrap.classList.remove('is-drawing');
  void pieWrap.offsetWidth;
  pieWrap.classList.add('is-drawing');

  const groups = pieWrap.querySelectorAll('.dashboard-sidebar-pie-slice-group');
  const sliceMs = DASH_SIDEBAR_PIE_TOTAL_MS / slices.length;

  groups.forEach((group, index) => {
    const slice = slices[index];
    if (!slice) return;
    const path = group.querySelector('.dashboard-sidebar-pie-slice');
    const labels = group.querySelectorAll('.dashboard-sidebar-pie-label');
    if (!path) return;

    const finalPath = dashDonutSlicePath(cx, cy, outerR, innerR, slice.startAngle, slice.endAngle);

    labels.forEach((label) => label.classList.remove('is-visible'));
    path.setAttribute('d', dashDonutSlicePath(cx, cy, outerR, innerR, slice.startAngle, slice.startAngle));

    const delay = index * sliceMs;
    const sweep = slice.endAngle - slice.startAngle;
    const startAt = performance.now() + delay;

    const tick = (now) => {
      const elapsed = now - startAt;
      if (elapsed < 0) {
        requestAnimationFrame(tick);
        return;
      }
      const progress = dashEaseOutCubic(Math.min(1, elapsed / sliceMs));
      const currentEnd = slice.startAngle + sweep * progress;
      const d = dashDonutSlicePath(cx, cy, outerR, innerR, slice.startAngle, currentEnd);
      if (d) path.setAttribute('d', d);
      else if (progress >= 1 && finalPath) path.setAttribute('d', finalPath);

      if (progress < 1) {
        requestAnimationFrame(tick);
        return;
      }
      if (finalPath) path.setAttribute('d', finalPath);
      labels.forEach((label) => label.classList.add('is-visible'));
    };
    requestAnimationFrame(tick);
  });

  window.setTimeout(() => pieWrap.classList.remove('is-drawing'), DASH_SIDEBAR_PIE_TOTAL_MS + 50);
}

function dashBindSidebarPieHover(pieWrap, {
  highlightWrap = null,
  highlightSidebarRoot = null,
  items = [],
  checkedKeys = null,
  itemKeys = [],
  onSolo = null,
  onShowAll = null,
  onHide = null,
} = {}) {
  if (!pieWrap) return;
  const itemByKey = new Map(items.map((item) => [item.key, item]));
  const canHighlight = Boolean(highlightWrap && highlightSidebarRoot);
  const canMenu = Boolean(onSolo && onShowAll && onHide && checkedKeys);
  pieWrap.querySelectorAll('.dashboard-sidebar-pie-slice-group[data-series-key]').forEach((group) => {
    const key = group.getAttribute('data-series-key');
    if (!key) return;
    if (canHighlight) {
      group.addEventListener('mouseenter', () => dashSetSeriesHighlight(
        highlightWrap,
        key,
        true,
        highlightSidebarRoot,
        { scrollSidebar: true },
      ));
      group.addEventListener('mouseleave', () => dashSetSeriesHighlight(
        highlightWrap,
        key,
        false,
        highlightSidebarRoot,
      ));
    }
    if (canMenu) {
      group.addEventListener('contextmenu', (ev) => {
        const item = itemByKey.get(key);
        if (!item) return;
        ev.preventDefault();
        dashOpenSeriesVisibilityContextMenu(ev.clientX, ev.clientY, {
          title: item.name,
          key,
          checkedKeys,
          itemKeys,
          onSolo,
          onShowAll,
          onHide,
        });
      });
    }
  });
}

function dashRenderSidebarPieChart(pieHost, items, checkedKeys, colorMap, {
  highlightWrap = null,
  highlightSidebarRoot = null,
  centerTitleLines = null,
  itemKeys = [],
  onSolo = null,
  onShowAll = null,
  onHide = null,
  animate = false,
} = {}) {
  const slices = dashBuildPieChartSlices(items, checkedKeys, colorMap);
  pieHost.replaceChildren();

  const cx = DASH_SIDEBAR_PIE_SIZE / 2;
  const cy = DASH_SIDEBAR_PIE_SIZE / 2;
  const outerR = DASH_SIDEBAR_PIE_SIZE / 2 - DASH_SIDEBAR_PIE_OUTER_INSET;
  const innerR = outerR - DASH_SIDEBAR_PIE_RING_WIDTH;

  // チェックなしでも円グラフ枠の高さを維持する（リスト領域が急に広がらないように）
  if (!slices.length) {
    const pieWrap = document.createElement('div');
    pieWrap.className = 'dashboard-sidebar-pie-wrap is-empty';
    const centerTitle = dashRenderPieCenterTitle(centerTitleLines, cx, cy);
    const emptyLabel = centerTitle
      ? ''
      : `<text class="dashboard-sidebar-pie-empty-label" x="${cx}" y="${cy}" text-anchor="middle" dominant-baseline="middle">—</text>`;
    pieWrap.innerHTML = `
    <svg class="dashboard-sidebar-pie-svg" viewBox="0 0 ${DASH_SIDEBAR_PIE_SIZE} ${DASH_SIDEBAR_PIE_SIZE}" aria-hidden="true">
      <path class="dashboard-sidebar-pie-empty-ring" d="${dashDonutSlicePath(cx, cy, outerR, innerR, 0, 360)}" />
      ${centerTitle}
      ${emptyLabel}
    </svg>`;
    pieHost.append(pieWrap);
    return;
  }

  const groups = slices.map((slice) => {
    const sweep = slice.endAngle - slice.startAngle;
    const midAngle = slice.startAngle + sweep / 2;
    const labels = dashRenderPieSliceLabels(slice.pieLabel, slice.pct, sweep, cx, cy, outerR, innerR, midAngle);
    const initialPath = dashDonutSlicePath(cx, cy, outerR, innerR, slice.startAngle, slice.startAngle);
    return `<g class="dashboard-sidebar-pie-slice-group" data-series-key="${dashEscapeHtml(slice.key)}" data-slice-index="${slice.index}" style="--slice-index:${slice.index}">
      <path class="dashboard-sidebar-pie-slice" d="${initialPath || `M ${cx} ${cy} Z`}" fill="${slice.color}"><title>${dashEscapeHtml(slice.name)} ${slice.pct.toFixed(1)}%</title></path>
      ${labels}
    </g>`;
  }).join('');
  const centerTitle = dashRenderPieCenterTitle(centerTitleLines, cx, cy);

  const pieWrap = document.createElement('div');
  pieWrap.className = 'dashboard-sidebar-pie-wrap';
  pieWrap.innerHTML = `
    <svg class="dashboard-sidebar-pie-svg" viewBox="0 0 ${DASH_SIDEBAR_PIE_SIZE} ${DASH_SIDEBAR_PIE_SIZE}" aria-hidden="true">
      <g class="dashboard-sidebar-pie-slices">${groups}</g>
      ${centerTitle}
    </svg>`;
  pieHost.append(pieWrap);
  dashBindSidebarPieHover(pieWrap, {
    highlightWrap,
    highlightSidebarRoot,
    items,
    checkedKeys,
    itemKeys,
    onSolo,
    onShowAll,
    onHide,
  });
  dashPlaySidebarPieSweepAnimation(pieWrap, slices, cx, cy, outerR, innerR, { animate });
}

function dashRenderSvgGroupedBarChart(container, series, labels, {
  title,
  legend,
  headerClass,
  targetTicks = 6,
  drilldownCtx = null,
  animate = false,
}) {
  const viewportScale = getViewportScale();
  const width = dashMeasureChartInnerWidth(container, 900);
  const fallbackHeight = Math.round(DASH_MAIN_CHART_BAR_HEIGHT * viewportScale);
  const allValues = series.flatMap((s) => s.values.map((v) => Math.abs(v ?? 0)));
  const dataMax = Math.max(0, ...allValues, 0);
  const paddedMax = dataMax > 0 ? dataMax * 1.08 : 1;
  const yAxis = dashComputeYAxisScale(0, paddedMax, { clampMinZero: true, targetTicks });
  const leftPad = dashComputeAxisLeftPad(yAxis.ticks, viewportScale);
  const legendHtml = legend.map((item) =>
    `<span class="dashboard-chart-legend-chip"><span class="dashboard-chart-legend-swatch" style="background:${item.color}"></span>${dashEscapeHtml(item.label)}</span>`,
  ).join('');

  dashRenderWithMeasuredHeight(container, fallbackHeight, '.dashboard-bar-chart-wrap', (chartHeight) => {
    const layout = dashChartLayout({ width, height: chartHeight, left: leftPad, right: 16, hasLegend: false });
    const { pad, plotW, plotH, plotBottom, height } = layout;
    const clipId = dashNextGradId('clip');
    const yScale = dashMakeYScale(yAxis, pad, plotH);
    const groupCount = labels.length;
    const barGroupW = plotW / Math.max(1, groupCount);
    let barGap = 4 * viewportScale;
    // 上限を固定 px でなく月枠幅にも追従させ、広い画面で棒間の隙間が開きすぎないようにする
    const barWMax = Math.max(22 * viewportScale, (barGroupW * 0.62) / series.length);
    let barW = Math.min(barWMax, Math.max(6, (barGroupW - barGap) / series.length - 4));
    let totalBarWidth = series.length * barW + (series.length - 1) * barGap;
    // 全期表示などで月枠に収まらない場合は隙間を詰めて棒を細くし、
    // 隣の月の棒の裏に支出が隠れないよう必ず枠内に収める
    if (totalBarWidth > barGroupW) {
      barGap = Math.max(0, Math.min(barGap, barGroupW * 0.08));
      barW = Math.max(1, (barGroupW - (series.length - 1) * barGap - 1) / series.length);
      totalBarWidth = series.length * barW + (series.length - 1) * barGap;
    }
    const barRx = Math.min(2, barW / 2).toFixed(2);

    const gridLines = dashRenderYAxisGrid(yAxis, yScale, pad, width);

    let bars = '';
    labels.forEach((label, gi) => {
      const groupLeft = pad.left + barGroupW * gi;
      const cx = groupLeft + barGroupW / 2;
      series.forEach((s, si) => {
        const val = Math.abs(s.values[gi] ?? 0);
        const x = cx - totalBarWidth / 2 + si * (barW + barGap);
        const y = yScale(val);
        bars += `<rect class="dashboard-chart-bar" data-month-index="${gi}" data-series-index="${si}" x="${x}" y="${y}" width="${barW}" height="${Math.max(0, plotBottom - y)}" fill="${s.color}" rx="${barRx}"/>`;
      });
    });

    const xScale = (i) => pad.left + barGroupW * i + barGroupW / 2;
    const xLabels = dashRenderXAxisLabelsTwoRow(labels, xScale, layout, { stepPx: barGroupW });

    container.innerHTML = `
    <div class="dashboard-chart-title ${headerClass ?? ''}">${title}</div>
    <div class="dashboard-bar-chart-wrap">
      <svg class="dashboard-chart-svg" viewBox="0 0 ${width} ${height}" preserveAspectRatio="xMidYMid meet">
        <defs>${dashRenderPlotClip(layout, clipId)}</defs>
        ${gridLines}
        <g clip-path="url(#${clipId})">${bars}</g>
        ${dashRenderBarChartInteractionMarkup(pad, plotW, plotH)}
        ${xLabels}
      </svg>
      ${dashRenderBarChartTooltipMarkup()}
    </div>
    <div class="dashboard-chart-legend-grid">${legendHtml}</div>`;
    dashBindGroupedBarChartHover(container, { series, labels, layout, xScale, yScale, drilldownCtx });
  });
  dashPlayChartDrawAnimation(container, { animate });
}

function dashFormatDisplayYenParts(value) {
  if (value === undefined || value === null || !Number.isFinite(Number(value))) {
    return null;
  }
  const n = Number(value);
  return {
    sign: n < 0 ? '-' : '',
    amount: Math.abs(n).toLocaleString('ja-JP'),
  };
}

function dashFormatDisplayYenText(value) {
  const parts = dashFormatDisplayYenParts(value);
  if (!parts) return '—';
  return `${parts.sign}${DASHBOARD_YEN}${parts.amount}`;
}

function dashFormatDisplayYenHtml(value) {
  const parts = dashFormatDisplayYenParts(value);
  if (!parts) return '—';
  const n = Number(value);
  const negClass = n < 0 ? ' amount-negative' : '';
  return `<span class="dashboard-yen-value${negClass}">${parts.sign}<span class="dashboard-yen-mark">${DASHBOARD_YEN}</span>${parts.amount}</span>`;
}

function dashFormatAxisYen(value) {
  return dashFormatDisplayYenText(Math.round(value));
}

function dashFormatSidebarYenHtml(value) {
  return dashFormatDisplayYenHtml(value);
}

function dashSmoothCurvePath(points) {
  if (points.length === 0) return '';
  if (points.length === 1) return `M ${points[0].x} ${points[0].y}`;
  if (points.length === 2) {
    return `M ${points[0].x} ${points[0].y} L ${points[1].x} ${points[1].y}`;
  }
  let d = `M ${points[0].x} ${points[0].y}`;
  for (let i = 0; i < points.length - 1; i += 1) {
    const p0 = points[Math.max(0, i - 1)];
    const p1 = points[i];
    const p2 = points[i + 1];
    const p3 = points[Math.min(points.length - 1, i + 2)];
    const cp1x = p1.x + (p2.x - p0.x) / 6;
    const cp1y = p1.y + (p2.y - p0.y) / 6;
    const cp2x = p2.x - (p3.x - p1.x) / 6;
    const cp2y = p2.y - (p3.y - p1.y) / 6;
    d += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p2.x} ${p2.y}`;
  }
  return d;
}

function dashNearestLineChartIndex(svgX, labels, xScale) {
  if (labels.length <= 1) return 0;
  let bestIdx = 0;
  let bestDist = Infinity;
  for (let i = 0; i < labels.length; i += 1) {
    const dist = Math.abs(xScale(i) - svgX);
    if (dist < bestDist) {
      bestDist = dist;
      bestIdx = i;
    }
  }
  return bestIdx;
}

function dashSvgClientToView(svg, clientX, clientY) {
  const rect = svg.getBoundingClientRect();
  const vb = svg.viewBox.baseVal;
  if (!rect.width || !rect.height) return { x: 0, y: 0 };
  return {
    x: ((clientX - rect.left) / rect.width) * vb.width,
    y: ((clientY - rect.top) / rect.height) * vb.height,
  };
}

function dashSvgViewToClient(svg, viewX, viewY) {
  const rect = svg.getBoundingClientRect();
  const vb = svg.viewBox.baseVal;
  return {
    x: rect.left + (viewX / vb.width) * rect.width,
    y: rect.top + (viewY / vb.height) * rect.height,
  };
}

function dashBindLineChartHover(container, {
  values,
  labels,
  layout,
  xScale,
  yScale,
  prevValues = null,
  prevPrevValues = null,
}) {
  const wrap = container.querySelector('.dashboard-line-chart-wrap');
  const svg = container.querySelector('.dashboard-chart-svg');
  const hoverRect = svg?.querySelector('.dashboard-line-chart-hover');
  const snapLine = svg?.querySelector('.dashboard-line-chart-snap-line');
  const snapDotCurrent = svg?.querySelector('.dashboard-line-chart-snap-dot--current');
  const snapDotPrev = svg?.querySelector('.dashboard-line-chart-snap-dot--prev');
  const snapDotPrevPrev = svg?.querySelector('.dashboard-line-chart-snap-dot--prev-prev');
  const tooltip = container.querySelector('.dashboard-line-chart-tooltip');
  const monthEl = tooltip?.querySelector('.dashboard-line-chart-tooltip-month');
  const rowsEl = tooltip?.querySelector('.dashboard-line-chart-tooltip-rows');
  if (!wrap || !svg || !hoverRect || !snapLine || !snapDotCurrent || !tooltip || !monthEl || !rowsEl) return;

  const { plotTop, plotBottom } = layout;
  const hasPrev = Boolean(prevValues?.length);
  const hasPrevPrev = Boolean(prevPrevValues?.length);
  const hasComparison = hasPrev || hasPrevPrev;

  const hide = () => {
    snapLine.setAttribute('opacity', '0');
    snapDotCurrent.setAttribute('opacity', '0');
    snapDotPrev?.setAttribute('opacity', '0');
    snapDotPrevPrev?.setAttribute('opacity', '0');
    tooltip.hidden = true;
  };

  const showAt = (idx) => {
    const x = xScale(idx);
    const val = values[idx] ?? 0;
    const y = yScale(val);
    snapLine.setAttribute('x1', String(x));
    snapLine.setAttribute('x2', String(x));
    snapLine.setAttribute('y1', String(plotTop));
    snapLine.setAttribute('y2', String(plotBottom));
    snapLine.setAttribute('opacity', '1');
    snapDotCurrent.setAttribute('cx', String(x));
    snapDotCurrent.setAttribute('cy', String(y));
    snapDotCurrent.setAttribute('opacity', '1');

    const rows = hasComparison
      ? [{ label: DASHBOARD_CURRENT_PERIOD, value: val }]
      : [{ label: '', value: val }];
    const anchorY = y;

    if (hasPrev && snapDotPrev) {
      const prevVal = prevValues[idx] ?? 0;
      const prevY = yScale(prevVal);
      snapDotPrev.setAttribute('cx', String(x));
      snapDotPrev.setAttribute('cy', String(prevY));
      snapDotPrev.setAttribute('opacity', '0.35');
      rows.push({ label: DASHBOARD_PREV_PERIOD, value: prevVal });
    } else {
      snapDotPrev?.setAttribute('opacity', '0');
    }

    if (hasPrevPrev && snapDotPrevPrev) {
      const prevPrevVal = prevPrevValues[idx] ?? 0;
      const prevPrevY = yScale(prevPrevVal);
      snapDotPrevPrev.setAttribute('cx', String(x));
      snapDotPrevPrev.setAttribute('cy', String(prevPrevY));
      snapDotPrevPrev.setAttribute('opacity', '0.08');
      rows.push({ label: DASHBOARD_PREV_PREV_PERIOD, value: prevPrevVal });
    } else {
      snapDotPrevPrev?.setAttribute('opacity', '0');
    }

    monthEl.textContent = labels[idx] ?? '';
    rowsEl.innerHTML = dashRenderChartTooltipRowsHtml(rows);
    tooltip.hidden = false;
    dashPositionChartTooltip(wrap, svg, tooltip, x, anchorY);
  };

  hoverRect.addEventListener('mousemove', (ev) => {
    const { x: svgX } = dashSvgClientToView(svg, ev.clientX, ev.clientY);
    showAt(dashNearestLineChartIndex(svgX, labels, xScale));
  });
  hoverRect.addEventListener('mouseleave', hide);
}

function dashPeekChartElementUnder(hoverRect, clientX, clientY, selector) {
  hoverRect.style.pointerEvents = 'none';
  const el = document.elementFromPoint(clientX, clientY);
  hoverRect.style.pointerEvents = 'all';
  return el?.closest(selector) ?? null;
}

/**
 * 積み上げ棒のヒット判定。全期表示などで棒が細いとき elementFromPoint が外れやすいため、
 * 月枠の X と積み上げ Y から系列を幾何的に特定する。
 */
function dashHitTestStackedBar(series, labels, xScale, yScale, svg, clientX, clientY, layout = null) {
  if (!series?.length || !labels?.length || !svg) return null;
  const { x: svgX, y: svgY } = dashSvgClientToView(svg, clientX, clientY);
  if (layout) {
    const { pad, plotW, plotH } = layout;
    if (svgX < pad.left || svgX > pad.left + plotW) return null;
    if (svgY < pad.top || svgY > pad.top + plotH) return null;
  }
  const monthIdx = dashNearestLineChartIndex(svgX, labels, xScale);
  let cumulative = 0;
  let hit = null;
  for (const s of series) {
    const val = Math.abs(s.values[monthIdx] ?? 0);
    if (val === 0) continue;
    const yTop = yScale(cumulative + val);
    const yBottom = yScale(cumulative);
    cumulative += val;
    // 下から積むので、後から当たった方が上のセグメント
    if (svgY >= yTop && svgY <= yBottom) {
      hit = { key: s.key, series: s, monthIdx, yTop, yBottom };
    }
  }
  return hit;
}

function dashRenderChartTooltipRowsHtml(rows) {
  return rows.map((r) => {
    const swatch = r.color
      ? `<span class="dashboard-bar-chart-tooltip-swatch" style="background:${r.color}"></span>`
      : '';
    return `<div class="dashboard-bar-chart-tooltip-row">${swatch}<span class="dashboard-bar-chart-tooltip-label">${dashEscapeHtml(r.label)}</span><span class="dashboard-bar-chart-tooltip-value">${dashFormatDisplayYenHtml(r.value)}</span></div>`;
  }).join('');
}

function dashPositionChartTooltip(wrap, svg, tooltip, viewX, viewY) {
  const wrapRect = wrap.getBoundingClientRect();
  const { x: clientX, y: clientY } = dashSvgViewToClient(svg, viewX, viewY);
  tooltip.style.left = `${clientX - wrapRect.left}px`;
  tooltip.style.top = `${clientY - wrapRect.top}px`;
}

function dashShowChartBarTooltip({ wrap, svg, tooltip, monthEl, rowsEl, monthLabel, rows, anchorX, anchorY }) {
  monthEl.textContent = monthLabel;
  rowsEl.innerHTML = dashRenderChartTooltipRowsHtml(rows);
  tooltip.hidden = false;
  dashPositionChartTooltip(wrap, svg, tooltip, anchorX, anchorY);
}

function dashRenderBarChartInteractionMarkup(pad, plotW, plotH) {
  return `<g class="dashboard-bar-chart-interaction">
    <rect class="dashboard-bar-chart-hover" x="${pad.left}" y="${pad.top}" width="${plotW}" height="${plotH}"/>
  </g>`;
}

function dashRenderBarChartTooltipMarkup() {
  return `<div class="dashboard-bar-chart-tooltip" hidden>
    <span class="dashboard-bar-chart-tooltip-month"></span>
    <div class="dashboard-bar-chart-tooltip-rows"></div>
  </div>`;
}

function dashBindGroupedBarChartHover(container, { series, labels, layout, xScale, yScale, drilldownCtx = null }) {
  const wrap = container.querySelector('.dashboard-bar-chart-wrap');
  const svg = container.querySelector('.dashboard-chart-svg');
  const hoverRect = svg?.querySelector('.dashboard-bar-chart-hover');
  const tooltip = container.querySelector('.dashboard-bar-chart-tooltip');
  const monthEl = tooltip?.querySelector('.dashboard-bar-chart-tooltip-month');
  const rowsEl = tooltip?.querySelector('.dashboard-bar-chart-tooltip-rows');
  if (!wrap || !svg || !hoverRect || !tooltip || !monthEl || !rowsEl) return;

  const { plotBottom } = layout;

  const hide = () => {
    tooltip.hidden = true;
    wrap.classList.remove('is-journal-drilldown');
  };

  hoverRect.addEventListener('mousemove', (ev) => {
    const { x: svgX } = dashSvgClientToView(svg, ev.clientX, ev.clientY);
    const monthIdx = dashNearestLineChartIndex(svgX, labels, xScale);
    const anchorX = xScale(monthIdx);
    const bar = dashPeekChartElementUnder(hoverRect, ev.clientX, ev.clientY, '.dashboard-chart-bar');
    let rows;
    let anchorY = plotBottom;
    if (bar && bar.closest('svg') === svg) {
      const gi = Number(bar.getAttribute('data-month-index'));
      const si = Number(bar.getAttribute('data-series-index'));
      const s = series[si];
      if (s) {
        rows = [{ label: s.label, value: Math.abs(s.values[gi] ?? 0), color: s.color }];
        anchorY = Number(bar.getAttribute('y') ?? plotBottom);
      }
    }
    if (!rows) {
      const inflow = Math.abs(series[0]?.values[monthIdx] ?? 0);
      const outflow = Math.abs(series[1]?.values[monthIdx] ?? 0);
      rows = series.map((s) => ({
        label: s.label,
        value: Math.abs(s.values[monthIdx] ?? 0),
        color: s.color,
      }));
      rows.push({ label: DASHBOARD_INFLOW_MINUS_OUTFLOW, value: inflow - outflow });
      series.forEach((s) => {
        const val = Math.abs(s.values[monthIdx] ?? 0);
        if (val > 0) anchorY = Math.min(anchorY, yScale(val));
      });
    }
    wrap.classList.toggle(
      'is-journal-drilldown',
      Boolean(dashResolveGroupedChartDrilldown(hoverRect, ev, svg, drilldownCtx)),
    );
    dashShowChartBarTooltip({
      wrap,
      svg,
      tooltip,
      monthEl,
      rowsEl,
      monthLabel: labels[monthIdx] ?? '',
      rows,
      anchorX,
      anchorY,
    });
  });
  hoverRect.addEventListener('mouseleave', hide);
  hoverRect.addEventListener('dblclick', (ev) => {
    const target = dashResolveGroupedChartDrilldown(hoverRect, ev, svg, drilldownCtx);
    if (!target) return;
    dashShowCfJournal(drilldownCtx, target.cfSectionId, target.cfRowId, target.month);
  });
}

function dashBindStackedBarChartHover(container, {
  series,
  labels,
  layout,
  xScale,
  yScale,
  highlightWrap,
  highlightSidebarRoot,
  breakdownItems = [],
  drilldownCtx = null,
  checkedKeys = null,
  itemKeys = [],
  onSolo = null,
  onShowAll = null,
  onHide = null,
}) {
  const wrap = container.querySelector('.dashboard-bar-chart-wrap');
  const svg = container.querySelector('.dashboard-chart-svg');
  const hoverRect = svg?.querySelector('.dashboard-bar-chart-hover');
  const tooltip = container.querySelector('.dashboard-bar-chart-tooltip');
  const monthEl = tooltip?.querySelector('.dashboard-bar-chart-tooltip-month');
  const rowsEl = tooltip?.querySelector('.dashboard-bar-chart-tooltip-rows');
  if (!wrap || !svg || !hoverRect || !tooltip || !monthEl || !rowsEl) return;

  const { plotBottom } = layout;
  const itemByKey = new Map(breakdownItems.map((item) => [item.key, item]));
  let activeKey = null;
  let activeFocusMonthIndex = null;

  const setHighlight = (key, focusMonthIndex = null) => {
    if (key === activeKey && focusMonthIndex === activeFocusMonthIndex) return;
    if (activeKey && highlightWrap) {
      dashSetSeriesHighlight(highlightWrap, activeKey, false, highlightSidebarRoot);
    }
    activeKey = key;
    activeFocusMonthIndex = focusMonthIndex;
    if (key && highlightWrap) {
      dashSetSeriesHighlight(highlightWrap, key, true, highlightSidebarRoot, {
        scrollSidebar: true,
        focusMonthIndex,
      });
    }
  };

  const hide = () => {
    tooltip.hidden = true;
    setHighlight(null);
    activeFocusMonthIndex = null;
    wrap.classList.remove('is-journal-drilldown');
  };

  hoverRect.addEventListener('mousemove', (ev) => {
    const { x: svgX } = dashSvgClientToView(svg, ev.clientX, ev.clientY);
    const monthIdx = dashNearestLineChartIndex(svgX, labels, xScale);
    const anchorX = xScale(monthIdx);
    const hit = dashHitTestStackedBar(series, labels, xScale, yScale, svg, ev.clientX, ev.clientY, layout);
    let rows;
    let anchorY = plotBottom;
    if (hit) {
      setHighlight(hit.key, hit.monthIdx);
      rows = [{ label: hit.series.label, value: Math.abs(hit.series.values[hit.monthIdx] ?? 0), color: hit.series.color }];
      anchorY = hit.yTop;
    }
    if (!rows) {
      setHighlight(null);
      const total = series.reduce((sum, s) => sum + Math.abs(s.values[monthIdx] ?? 0), 0);
      rows = [{ label: DASHBOARD_GOUKEI, value: total }];
      anchorY = yScale(total);
    }
    wrap.classList.toggle(
      'is-journal-drilldown',
      Boolean(dashResolveStackedChartDrilldown(hoverRect, ev, svg, itemByKey, drilldownCtx, {
        series,
        labels,
        xScale,
        yScale,
        layout,
      })),
    );
    dashShowChartBarTooltip({
      wrap,
      svg,
      tooltip,
      monthEl,
      rowsEl,
      monthLabel: labels[monthIdx] ?? '',
      rows,
      anchorX,
      anchorY,
    });
  });
  hoverRect.addEventListener('mouseleave', hide);
  hoverRect.addEventListener('contextmenu', (ev) => {
    if (!onSolo || !onShowAll || !onHide || !checkedKeys) return;
    const hit = dashHitTestStackedBar(series, labels, xScale, yScale, svg, ev.clientX, ev.clientY, layout);
    if (!hit) return;
    const item = itemByKey.get(hit.key);
    if (!item) return;
    ev.preventDefault();
    dashOpenSeriesVisibilityContextMenu(ev.clientX, ev.clientY, {
      title: item.name,
      key: hit.key,
      checkedKeys,
      itemKeys,
      onSolo,
      onShowAll,
      onHide,
    });
  });
  hoverRect.addEventListener('dblclick', (ev) => {
    const target = dashResolveStackedChartDrilldown(hoverRect, ev, svg, itemByKey, drilldownCtx, {
      series,
      labels,
      xScale,
      yScale,
      layout,
    });
    if (!target) return;
    dashShowJournal(drilldownCtx, target.item, target.month);
  });
}

function dashRenderSvgStackedBarChart(container, series, labels, {
  title,
  headerClass,
  targetTicks = 6,
  highlightWrap = null,
  highlightSidebarRoot = null,
  breakdownItems = null,
  drilldownCtx = null,
  checkedKeys = null,
  itemKeys = [],
  onSolo = null,
  onShowAll = null,
  onHide = null,
  animate = false,
}) {
  const viewportScale = getViewportScale();
  const width = dashMeasureChartInnerWidth(container, 900);
  const fallbackHeight = Math.round(DASH_MAIN_CHART_BAR_HEIGHT * viewportScale);
  const monthTotals = labels.map((_, gi) =>
    series.reduce((sum, s) => sum + Math.abs(s.values[gi] ?? 0), 0));
  const dataMax = Math.max(0, ...monthTotals, 0);
  const paddedMax = dataMax > 0 ? dataMax * 1.08 : 1;
  const yAxis = dashComputeYAxisScale(0, paddedMax, { clampMinZero: true, targetTicks });
  const leftPad = dashComputeAxisLeftPad(yAxis.ticks, viewportScale);
  const legendHtml = dashRenderStackedLegendHtml(series);

  dashRenderWithMeasuredHeight(container, fallbackHeight, '.dashboard-bar-chart-wrap', (chartHeight) => {
    const layout = dashChartLayout({ width, height: chartHeight, left: leftPad, right: 16, hasLegend: false });
    const { pad, plotW, plotH, plotBottom, plotTop, height } = layout;
    const clipId = dashNextGradId('clip');
    const yScale = dashMakeYScale(yAxis, pad, plotH);
    const groupCount = labels.length;
    const barGroupW = plotW / Math.max(1, groupCount);
    // 固定 px の上限をやめ、月枠幅の一定割合で棒の太さを画面幅に追従させる
    // （全期表示など月数が多い場合は月枠からはみ出さないよう細くする）
    const barW = Math.min(Math.max(8, barGroupW * 0.55), Math.max(1, barGroupW - 1));

    const gridLines = dashRenderYAxisGrid(yAxis, yScale, pad, width);

    let bars = '';
    labels.forEach((_, gi) => {
      const groupLeft = pad.left + barGroupW * gi;
      const cx = groupLeft + barGroupW / 2;
      const x = cx - barW / 2;
      let cumulative = 0;
      let columnBars = '';
      series.forEach((s) => {
        const val = Math.abs(s.values[gi] ?? 0);
        if (val === 0) return;
        const yTop = yScale(cumulative + val);
        const yBottom = yScale(cumulative);
        cumulative += val;
        columnBars += `<rect class="dashboard-chart-segment" data-series-key="${dashEscapeHtml(s.key)}" data-month-index="${gi}" x="${x}" y="${yTop}" width="${barW}" height="${Math.max(0, yBottom - yTop)}" fill="${s.color}" rx="1"/>`;
      });
      if (columnBars) {
        bars += `<g class="dashboard-chart-column" data-month-index="${gi}">${columnBars}</g>`;
      }
    });

    const xScale = (i) => pad.left + barGroupW * i + barGroupW / 2;
    const xLabels = dashRenderXAxisLabelsTwoRow(labels, xScale, layout, { stepPx: barGroupW });

    container.innerHTML = `
    <div class="dashboard-chart-title ${headerClass ?? ''}">${title}</div>
    <div class="dashboard-bar-chart-wrap dashboard-bar-chart-wrap--stacked-series">
      <svg class="dashboard-chart-svg" viewBox="0 0 ${width} ${height}" preserveAspectRatio="xMidYMid meet">
        <defs>${dashRenderPlotClip(layout, clipId)}</defs>
        ${gridLines}
        <g clip-path="url(#${clipId})">${bars}</g>
        ${dashRenderBarChartInteractionMarkup(pad, plotW, plotH)}
        <g class="dashboard-chart-highlight-layer"></g>
        ${xLabels}
      </svg>
      ${dashRenderBarChartTooltipMarkup()}
    </div>
    <div class="dashboard-chart-legend-grid">${legendHtml}</div>`;
    dashBindStackedBarChartHover(container, {
      series,
      labels,
      layout,
      xScale,
      yScale,
      highlightWrap,
      highlightSidebarRoot,
      breakdownItems: breakdownItems ?? [],
      drilldownCtx,
      checkedKeys,
      itemKeys,
      onSolo,
      onShowAll,
      onHide,
    });
    dashBindChartSeriesHover(container, highlightWrap, highlightSidebarRoot, {
      checkedKeys,
      itemKeys,
      breakdownItems: breakdownItems ?? [],
      onSolo,
      onShowAll,
      onHide,
    });
  });
  dashPlayChartDrawAnimation(container, { animate });
}

function dashRenderSvgGradientLineChart(container, values, labels, {
  title,
  headerClass,
  sectionFilterId,
  gradLow = 'var(--dashboard-line-grad-low)',
  gradHigh = 'var(--dashboard-line-grad-high)',
  includeZero = false,
  negativeTicksRed = false,
  prevValues = null,
  prevPrevValues = null,
  animate = false,
}) {
  const viewportScale = getViewportScale();
  const width = dashMeasureChartInnerWidth(container, 440);
  const fallbackHeight = Math.round(DASH_BOTTOM_CHART_HEIGHT * viewportScale);
  const scaleValues = [
    ...values,
    ...(prevValues ?? []),
    ...(prevPrevValues ?? []),
  ];
  const dataMin = Math.min(...scaleValues);
  const dataMax = Math.max(...scaleValues);
  const range = dataMax - dataMin || 1;
  const padRatio = 0.06;
  const paddedMin = dataMin - range * padRatio;
  const paddedMax = dataMax + range * padRatio;
  const yAxis = dashComputeYAxisScale(paddedMin, paddedMax, { includeZero, targetTicks: 5 });
  const leftPad = dashComputeAxisLeftPad(yAxis.ticks, viewportScale);

  dashRenderWithMeasuredHeight(container, fallbackHeight, '.dashboard-line-chart-wrap', (chartHeight) => {
    const layout = dashChartLayout({ width, height: chartHeight, left: leftPad, right: 12, hasLegend: false });
    const { pad, plotW, plotH, plotBottom, plotTop, height } = layout;
    const clipId = dashNextGradId('clip');
    const yScale = dashMakeYScale(yAxis, pad, plotH);
    const xScale = (i) => pad.left + (plotW * i) / Math.max(1, labels.length - 1);
    const gradId = dashNextGradId('line');

    let gridLines = dashRenderYAxisGrid(yAxis, yScale, pad, width, { negativeTicksRed });

    if (includeZero && yAxis.min < 0 && yAxis.max > 0) {
      const zeroY = yScale(0);
      gridLines += `<line x1="${pad.left}" y1="${zeroY}" x2="${width - pad.right}" y2="${zeroY}" class="dashboard-chart-zero"/>`;
    }

    const points = values.map((v, i) => ({ x: xScale(i), y: yScale(v) }));
    const path = dashSmoothCurvePath(points);
    let prevPrevPathMarkup = '';
    if (prevPrevValues?.length) {
      const prevPrevPoints = prevPrevValues.map((v, i) => ({ x: xScale(i), y: yScale(v ?? 0) }));
      const prevPrevPath = dashSmoothCurvePath(prevPrevPoints);
      prevPrevPathMarkup = `<g class="dashboard-line-chart-prev-prev"><path d="${prevPrevPath}" fill="none" stroke="url(#${gradId})" stroke-width="2.8" stroke-linecap="round" stroke-linejoin="round"/></g>`;
    }
    let prevPathMarkup = '';
    if (prevValues?.length) {
      const prevPoints = prevValues.map((v, i) => ({ x: xScale(i), y: yScale(v ?? 0) }));
      const prevPath = dashSmoothCurvePath(prevPoints);
      prevPathMarkup = `<g class="dashboard-line-chart-prev"><path d="${prevPath}" fill="none" stroke="url(#${gradId})" stroke-width="2.8" stroke-linecap="round" stroke-linejoin="round"/></g>`;
    }
    const xLabels = dashRenderXAxisLabelsTwoRow(labels, xScale, layout, { stepPx: plotW / Math.max(1, labels.length - 1) });

    container.innerHTML = `
    <div class="dashboard-chart-title ${headerClass ?? ''}">${title}</div>
    <div class="dashboard-line-chart-wrap">
      <svg class="dashboard-chart-svg" viewBox="0 0 ${width} ${height}" preserveAspectRatio="xMidYMid meet">
        <defs>
          ${dashRenderPlotClip(layout, clipId)}
          <linearGradient id="${gradId}" gradientUnits="userSpaceOnUse"
            x1="${pad.left}" y1="${plotBottom}" x2="${pad.left}" y2="${plotTop}">
            <stop offset="0%" stop-color="${gradLow}"/>
            <stop offset="100%" stop-color="${gradHigh}"/>
          </linearGradient>
        </defs>
        ${gridLines}
        <g clip-path="url(#${clipId})">
          ${prevPrevPathMarkup}
          ${prevPathMarkup}
          <path class="dashboard-line-chart-current" d="${path}" fill="none" stroke="url(#${gradId})" stroke-width="2.8" stroke-linecap="round" stroke-linejoin="round"/>
        </g>
        <g class="dashboard-line-chart-interaction">
          <line class="dashboard-line-chart-snap-line" x1="0" y1="0" x2="0" y2="0" opacity="0"/>
          <circle class="dashboard-line-chart-snap-dot dashboard-line-chart-snap-dot--current" cx="0" cy="0" r="4" opacity="0"/>
          <circle class="dashboard-line-chart-snap-dot dashboard-line-chart-snap-dot--prev" cx="0" cy="0" r="4" opacity="0"/>
          <circle class="dashboard-line-chart-snap-dot dashboard-line-chart-snap-dot--prev-prev" cx="0" cy="0" r="4" opacity="0"/>
          <rect class="dashboard-line-chart-hover"
            x="${pad.left}" y="${pad.top}" width="${plotW}" height="${plotH}"/>
        </g>
        ${xLabels}
      </svg>
      <div class="dashboard-line-chart-tooltip" hidden>
        <span class="dashboard-line-chart-tooltip-month"></span>
        <div class="dashboard-line-chart-tooltip-rows"></div>
      </div>
    </div>`;
    dashApplySectionFilterChartTitleStyle(
      container.querySelector('.dashboard-chart-title'),
      sectionFilterId,
    );
    dashBindLineChartHover(container, { values, labels, layout, xScale, yScale, prevValues, prevPrevValues });
  });
  dashPlayChartDrawAnimation(container, { animate });
}

function dashAppendSidebarRow(list, item, checkedKeys, onToggle, onSolo, {
  highlightWrap = null,
  highlightSidebarRoot = null,
  drilldownCtx = null,
  ensureChartMode = null,
  pctBase = 0,
  maxPct = 0,
  showPct = true,
  rowClass = '',
  itemKeys = [],
  onShowAll = null,
  onHide = null,
} = {}) {
  const pct = showPct && pctBase > 0 ? (Math.abs(item.total) / pctBase) * 100 : 0;
  const barWidth = showPct && maxPct > 0 ? (pct / maxPct) * 100 : 0;
  const row = document.createElement('div');
  row.className = `dashboard-sidebar-row${rowClass ? ` ${rowClass}` : ''}`;
  row.dataset.seriesKey = item.key;
  row.innerHTML = `
    <input type="checkbox" class="dashboard-sidebar-check" data-key="${dashEscapeHtml(item.key)}" title="${dashEscapeHtml(TIP_DASH_SIDEBAR_ITEM)}" ${checkedKeys.has(item.key) ? 'checked' : ''} />
    <span class="dashboard-sidebar-name" title="${dashEscapeHtml(item.name + '\n' + TIP_DASH_SIDEBAR_ITEM)}">${dashEscapeHtml(item.name)}</span>
    <span class="dashboard-sidebar-amount">${dashFormatSidebarYenHtml(item.total)}</span>
    ${showPct
    ? `<span class="dashboard-sidebar-pct-wrap">
        <span class="dashboard-sidebar-bar" style="width:${barWidth.toFixed(2)}%"></span>
        <span class="dashboard-sidebar-pct">${pct.toFixed(2)}%</span>
      </span>`
    : '<span class="dashboard-sidebar-pct-wrap dashboard-sidebar-pct-wrap--empty"></span>'}`;
  const input = row.querySelector('input');
  const nameEl = row.querySelector('.dashboard-sidebar-name');
  const amountEl = row.querySelector('.dashboard-sidebar-amount');
  input.addEventListener('click', (ev) => {
    if (ev.ctrlKey || ev.metaKey) {
      ev.preventDefault();
      dashRememberSidebarListScroll(input);
      ensureChartMode?.();
      onSolo?.(item.key);
    }
  });
  input.addEventListener('change', (ev) => {
    if (ev.ctrlKey || ev.metaKey) return;
    dashRememberSidebarListScroll(input);
    ensureChartMode?.();
    onToggle(item.key, ev.target.checked);
  });
  nameEl.addEventListener('click', (ev) => {
    dashRememberSidebarListScroll(nameEl);
    if (ev.ctrlKey || ev.metaKey) {
      ensureChartMode?.();
      onSolo?.(item.key);
      return;
    }
    ensureChartMode?.();
    input.checked = !input.checked;
    onToggle(item.key, input.checked);
  });
  if (onSolo && onShowAll && onHide) {
    row.addEventListener('contextmenu', (ev) => {
      ev.preventDefault();
      dashRememberSidebarListScroll(row);
      dashOpenSeriesVisibilityContextMenu(ev.clientX, ev.clientY, {
        title: item.name,
        key: item.key,
        checkedKeys,
        itemKeys,
        onSolo: (key) => {
          ensureChartMode?.();
          onSolo(key);
        },
        onShowAll: () => {
          ensureChartMode?.();
          onShowAll();
        },
        onHide: (key) => {
          ensureChartMode?.();
          onHide(key);
        },
      });
    });
  }
  if (dashCanShowJournal(drilldownCtx, item, DASHBOARD_GOUKEI)) {
    amountEl.classList.add('dashboard-has-journal-drilldown');
    amountEl.title = TIP_DRILLDOWN_JOURNAL;
    amountEl.addEventListener('dblclick', () => {
      dashShowJournal(drilldownCtx, item, DASHBOARD_GOUKEI);
    });
  }
  list.appendChild(row);
}

/** チェック操作前にリストのスクロール位置を state へ退避する */
function dashRememberSidebarListScroll(fromEl) {
  const list = fromEl?.closest?.('.dashboard-sidebar-list');
  const dashState = dashboardMountCtx?.state;
  if (!list || !dashState) return;
  const side = list.closest('.dashboard-sidebar-revenue')
    ? 'revenueListScrollTop'
    : list.closest('.dashboard-sidebar-expense')
      ? 'expenseListScrollTop'
      : null;
  if (!side) return;
  list.dataset.scrollReady = '1';
  dashState[side] = list.scrollTop;
}

/** リスト DOM を作り直さず、チェック状態と一括ボタンだけ同期する */
function dashSyncSidebarCheckState(sidebarEl, checkedKeys, itemKeys) {
  if (!sidebarEl) return;
  const inputs = [...sidebarEl.querySelectorAll('.dashboard-sidebar-check')];
  let checkedCount = 0;
  inputs.forEach((input) => {
    const key = input.getAttribute('data-key');
    if (key == null) return;
    const isChecked = checkedKeys.has(key);
    input.checked = isChecked;
    if (isChecked) checkedCount += 1;
  });
  // ボタンの disabled は画面上のチェックと一致させる（キー不整合で押せなくなるのを防ぐ）
  const allChecked = inputs.length > 0
    ? checkedCount === inputs.length
    : itemKeys.length > 0 && itemKeys.every((key) => checkedKeys.has(key));
  const checkAllBtn = sidebarEl.querySelector('[data-action="check-all"]');
  if (checkAllBtn) checkAllBtn.disabled = allChecked;
}

function dashRenderSidebarList(container, items, checkedKeys, totalLabel, headerClass, onToggle, {
  highlightWrap = null,
  highlightSidebarRoot = null,
  onCheckAll = null,
  onUncheckAll = null,
  onSolo = null,
  showBreakdownToggle = false,
  breakdownMode = 'account',
  onBreakdownModeChange = null,
  showSortToggle = false,
  sortMode = 'amount',
  onSortModeChange = null,
  drilldownCtx = null,
  ensureChartMode = null,
  deductionLabel = null,
  colorMap = null,
  pieCenterTitleLines = null,
  animate = false,
  /** state にスクロール位置を保持するキー（再描画・ResizeObserver 対策） */
  scrollStateKey = null,
} = {}) {
  const total = items.reduce((sum, item) => sum + item.total, 0);
  const mainItems = deductionLabel ? items.filter((item) => item.total > 0) : items;
  const deductionItems = deductionLabel ? items.filter((item) => item.total < 0) : [];
  const pctBase = deductionLabel
    ? mainItems.reduce((sum, item) => sum + item.total, 0)
    : total;

  const breakdownTabsHtml = showBreakdownToggle
    ? `<div class="dashboard-sidebar-breakdown-tabs" role="tablist">
      ${DASHBOARD_BREAKDOWN_MODES.map(
    (mode) => `<button type="button" class="dashboard-sidebar-breakdown-btn${breakdownMode === mode.id ? ' is-active' : ''}" data-breakdown-mode="${mode.id}" role="tab" title="${mode.title}">${mode.label}</button>`,
  ).join('')}
    </div>`
    : '';

  const sortTabsHtml = showSortToggle
    ? `<div class="dashboard-sidebar-breakdown-tabs dashboard-sidebar-sort-tabs" role="tablist">
      ${DASHBOARD_SIDEBAR_SORT_MODES.map(
    (mode) => `<button type="button" class="dashboard-sidebar-breakdown-btn${sortMode === mode.id ? ' is-active' : ''}" data-sort-mode="${mode.id}" role="tab" title="${mode.title}">${mode.label}</button>`,
  ).join('')}
    </div>`
    : '';

  const headerTabsHtml = breakdownTabsHtml || sortTabsHtml
    ? `<div class="dashboard-sidebar-header-tabs">${breakdownTabsHtml}${sortTabsHtml}</div>`
    : '';

  const allChecked = items.length > 0 && items.every((item) => checkedKeys.has(item.key));
  const bulkActionsHtml = `<div class="dashboard-sidebar-bulk-actions">
        <button type="button" class="dashboard-sidebar-breakdown-btn dashboard-sidebar-bulk-btn" data-action="check-all" title="${TIP_DASH_CHECK_ALL}"${allChecked ? ' disabled' : ''}>すべてチェック</button>
        <button type="button" class="dashboard-sidebar-breakdown-btn dashboard-sidebar-bulk-btn" data-action="uncheck-all" title="${TIP_DASH_UNCHECK_ALL}">すべて外す</button>
      </div>`;

  const header = document.createElement('div');
  header.className = `dashboard-sidebar-header ${headerClass}`;
  header.innerHTML = `
    <div class="dashboard-sidebar-header-top">
      <span class="dashboard-sidebar-total-label">${totalLabel}</span>
      <span class="dashboard-sidebar-total-value">${dashFormatSidebarYenHtml(total)}</span>
    </div>
    ${bulkActionsHtml}
    ${headerTabsHtml}`;
  header.querySelector('[data-action="check-all"]')?.addEventListener('click', (ev) => {
    ev.preventDefault();
    dashRememberSidebarListScroll(container.querySelector('.dashboard-sidebar-list'));
    ensureChartMode?.();
    onCheckAll?.();
  });
  header.querySelector('[data-action="uncheck-all"]')?.addEventListener('click', (ev) => {
    ev.preventDefault();
    dashRememberSidebarListScroll(container.querySelector('.dashboard-sidebar-list'));
    ensureChartMode?.();
    onUncheckAll?.();
  });
  if (showBreakdownToggle) {
    header.querySelectorAll('[data-breakdown-mode]').forEach((btn) => {
      btn.addEventListener('click', () => {
        ensureChartMode?.();
        onBreakdownModeChange?.(btn.dataset.breakdownMode);
      });
    });
  }
  if (showSortToggle) {
    header.querySelectorAll('[data-sort-mode]').forEach((btn) => {
      btn.addEventListener('click', () => {
        ensureChartMode?.();
        onSortModeChange?.(btn.dataset.sortMode);
      });
    });
  }

  const list = document.createElement('div');
  list.className = 'dashboard-sidebar-list';

  const maxPct = pctBase > 0
    ? Math.max(...mainItems.map((item) => (Math.abs(item.total) / pctBase) * 100), 0)
    : 0;

  const rowOptions = {
    highlightWrap,
    highlightSidebarRoot,
    drilldownCtx,
    ensureChartMode,
    pctBase,
    maxPct,
    itemKeys: items.map((item) => item.key),
    onShowAll: onCheckAll,
    onHide: (key) => onToggle(key, false),
  };

  for (const item of mainItems) {
    dashAppendSidebarRow(list, item, checkedKeys, onToggle, onSolo, rowOptions);
  }

  if (deductionItems.length) {
    const deductionHeader = document.createElement('div');
    deductionHeader.className = 'dashboard-sidebar-deduction-header';
    deductionHeader.textContent = deductionLabel;
    list.appendChild(deductionHeader);
    for (const item of deductionItems) {
      dashAppendSidebarRow(list, item, checkedKeys, onToggle, onSolo, {
        ...rowOptions,
        showPct: false,
        rowClass: 'dashboard-sidebar-row--deduction',
      });
    }
  }

  const pieHost = document.createElement('div');
  pieHost.className = 'dashboard-sidebar-pie';

  // 再描画でスクロール／フォーカスが先頭に戻らないように保持する
  // （操作直前に dashRememberSidebarListScroll で state へ退避済み）
  const dashState = dashboardMountCtx?.state;
  const prevList = container.querySelector('.dashboard-sidebar-list');
  if (dashState && scrollStateKey && prevList?.dataset.scrollReady === '1') {
    dashState[scrollStateKey] = prevList.scrollTop;
  }
  const savedScrollTop = (dashState && scrollStateKey && Number.isFinite(dashState[scrollStateKey]))
    ? dashState[scrollStateKey]
    : 0;
  const activeEl = document.activeElement;
  const focusKey = (activeEl instanceof HTMLElement
    && prevList?.contains(activeEl)
    && activeEl.matches('.dashboard-sidebar-check'))
    ? activeEl.getAttribute('data-key')
    : null;

  container.replaceChildren(header, list, pieHost);
  dashPlaySidebarBarDrawAnimation(container, { animate });
  if (colorMap) {
    dashRenderSidebarPieChart(pieHost, mainItems, checkedKeys, colorMap, {
      highlightWrap,
      highlightSidebarRoot,
      centerTitleLines: pieCenterTitleLines,
      itemKeys: items.map((item) => item.key),
      onSolo: (key) => {
        ensureChartMode?.();
        onSolo?.(key);
      },
      onShowAll: () => {
        ensureChartMode?.();
        onCheckAll?.();
      },
      onHide: (key) => {
        ensureChartMode?.();
        onToggle(key, false);
      },
      animate,
    });
  }

  const restoreListView = () => {
    list.scrollTop = savedScrollTop;
    list.dataset.scrollReady = '1';
    if (dashState && scrollStateKey) dashState[scrollStateKey] = list.scrollTop;
    if (focusKey == null) return;
    const escaped = dashEscapeSeriesKeyForSelector(focusKey);
    const nextFocus = list.querySelector(`.dashboard-sidebar-check[data-key="${escaped}"]`);
    nextFocus?.focus({ preventScroll: true });
  };
  restoreListView();
  requestAnimationFrame(() => {
    restoreListView();
    requestAnimationFrame(restoreListView);
  });

  if (dashState && scrollStateKey) {
    list.addEventListener('scroll', () => {
      if (list.dataset.scrollReady !== '1') return;
      dashState[scrollStateKey] = list.scrollTop;
    }, { passive: true });
  }
}

function dashRenderDashboardContent(wrap, ctx, {
  animate = false,
  animateMainChart = false,
  /** サイドバーリストは維持し、チェック同期と円グラフだけ更新する */
  preserveSidebars = false,
  /** チェック変更の影響がない利益率・預金・収支棒は再描画しない */
  skipUnaffectedCharts = false,
} = {}) {
  dashCloseChartContextMenu();
  // 下部チャートを残したまま主チャートだけ差し替えるとき、ID 衝突を避けるため seq はリセットしない
  if (!skipUnaffectedCharts) dashGradientSeq = 0;
  const { data, prevData, prevPrevData, appSettings, state } = ctx;
  const allPeriods = ctx.allPeriods ?? null;
  const periodRange = ctx.periodRange ?? { from: appSettings.fiscalPeriod, to: appSettings.fiscalPeriod };
  const periodStorageKey = allPeriods?.length
    ? dashMultiPeriodStorageKey(periodRange.from, periodRange.to)
    : periodRange.from;
  const mainChartAnimate = animate || animateMainChart;
  const drilldownCtx = dashGetDrilldownCtx(ctx);
  const sections = data?.sections ?? [];
  if (!state.revenueBreakdownMode) state.revenueBreakdownMode = DASHBOARD_DEFAULT_REVENUE_BREAKDOWN_MODE;
  if (!state.expenseBreakdownMode) state.expenseBreakdownMode = DASHBOARD_DEFAULT_EXPENSE_BREAKDOWN_MODE;
  if (state.revenueSortMode == null) state.revenueSortMode = DASHBOARD_DEFAULT_SORT_MODE;
  if (state.expenseSortMode == null) state.expenseSortMode = DASHBOARD_DEFAULT_SORT_MODE;
  const revenueBreakdownMode = state.revenueBreakdownMode;
  const expenseBreakdownMode = state.expenseBreakdownMode;
  const revenueSortMode = state.revenueSortMode;
  const expenseSortMode = state.expenseSortMode;
  const prevRevenueItems = state.lastRevenueItems ?? null;
  const prevExpenseItems = state.lastExpenseItems ?? null;
  const prevRevenueMode = state.lastRevenueBreakdownMode ?? revenueBreakdownMode;
  const prevExpenseMode = state.lastExpenseBreakdownMode ?? expenseBreakdownMode;
  // 全期モードでは全期分の内訳を合算して使う
  const collectItems = (sectionIds, mode) => (allPeriods
    ? dashCollectAllPeriodBreakdownItems(allPeriods, sectionIds, mode)
    : dashCollectBreakdownItems(sections, sectionIds, mode));
  const revenueItems = dashSortBreakdownItems(
    collectItems(REVENUE_SECTION_IDS, revenueBreakdownMode),
    revenueSortMode,
  );
  const expenseItems = dashSortBreakdownItems(
    collectItems(EXPENSE_SECTION_IDS, expenseBreakdownMode),
    expenseSortMode,
  );
  const allItems = [...revenueItems, ...expenseItems];
  const allKeys = allItems.map((i) => i.key);
  if (state.revenueCheckAll == null || state.expenseCheckAll == null) {
    dashSyncSideCheckAllFlags(state, revenueItems, expenseItems);
  }
  if (state.pendingPeriodRemap && prevRevenueItems && prevExpenseItems) {
    state.checkedKeys = dashRemapPeriodSideCheckedKeys(
      state.checkedKeys,
      prevRevenueItems,
      revenueItems,
      state.revenueCheckAll,
      prevRevenueMode,
      revenueBreakdownMode,
    );
    state.checkedKeys = dashRemapPeriodSideCheckedKeys(
      state.checkedKeys,
      prevExpenseItems,
      expenseItems,
      state.expenseCheckAll,
      prevExpenseMode,
      expenseBreakdownMode,
    );
    state.seenKeys = new Set(allKeys);
    state.pendingPeriodRemap = false;
    dashSaveCheckedKeys(periodStorageKey, state.checkedKeys);
  } else if (!state.initialized) {
    state.checkedKeys = dashLoadCheckedKeys(periodStorageKey, allKeys);
    state.seenKeys = new Set(allKeys);
    state.initialized = true;
    dashSyncSideCheckAllFlags(state, revenueItems, expenseItems);
  } else {
    if (prevRevenueMode !== revenueBreakdownMode && prevRevenueItems) {
      state.checkedKeys = dashRemapPeriodSideCheckedKeys(
        state.checkedKeys,
        prevRevenueItems,
        revenueItems,
        state.revenueCheckAll,
        prevRevenueMode,
        revenueBreakdownMode,
      );
      state.seenKeys = new Set(allKeys);
      dashSaveCheckedKeys(periodStorageKey, state.checkedKeys);
    }
    if (prevExpenseMode !== expenseBreakdownMode && prevExpenseItems) {
      state.checkedKeys = dashRemapPeriodSideCheckedKeys(
        state.checkedKeys,
        prevExpenseItems,
        expenseItems,
        state.expenseCheckAll,
        prevExpenseMode,
        expenseBreakdownMode,
      );
      state.seenKeys = new Set(allKeys);
      dashSaveCheckedKeys(periodStorageKey, state.checkedKeys);
    }
    const revenueKeySet = new Set(revenueItems.map((i) => i.key));
    let keysAdded = false;
    for (const key of allKeys) {
      if (!state.seenKeys.has(key)) {
        state.seenKeys.add(key);
        const shouldCheck = revenueKeySet.has(key) ? state.revenueCheckAll : state.expenseCheckAll;
        if (shouldCheck) {
          state.checkedKeys.add(key);
          keysAdded = true;
        }
      }
    }
    if (keysAdded) dashSaveCheckedKeys(periodStorageKey, state.checkedKeys);
  }
  state.lastRevenueItems = revenueItems;
  state.lastExpenseItems = expenseItems;
  state.lastRevenueBreakdownMode = revenueBreakdownMode;
  state.lastExpenseBreakdownMode = expenseBreakdownMode;

  const viewPeriod = periodRange.from;
  const chartAppSettings = allPeriods?.length
    ? appSettings
    : { ...appSettings, fiscalPeriod: viewPeriod };

  // 複数期モードでは各期の月次系列を連結し、前期・前々期の比較線は表示しない
  const monthly = allPeriods
    ? dashBuildMonthlySeriesAllPeriods(allPeriods, appSettings)
    : dashBuildMonthlySeries(data, chartAppSettings);
  const monthLabels = monthly.map((m) => m.label);
  const prevMonthly = !allPeriods && prevData && viewPeriod > 1
    ? dashBuildMonthlySeries(prevData, {
      ...chartAppSettings,
      fiscalPeriod: viewPeriod - 1,
    })
    : null;
  const prevPrevMonthly = !allPeriods && prevPrevData && viewPeriod > 2
    ? dashBuildMonthlySeries(prevPrevData, {
      ...chartAppSettings,
      fiscalPeriod: viewPeriod - 2,
    })
    : null;

  const toolbar = wrap.querySelector('.dashboard-toolbar');
  if (toolbar) {
    const periodLabel = allPeriods?.length
      ? dashFormatPeriodRangeLabel(periodRange.from, periodRange.to)
      : formatFiscalPeriodLabel(periodRange.from);
    toolbar.querySelector('.dashboard-title').textContent =
      `${periodLabel} ダッシュボード`;
    toolbar.querySelectorAll('.dashboard-mode-tabs .dashboard-mode-btn').forEach((btn) => {
      btn.classList.toggle('is-active', btn.dataset.mode === state.chartMode);
    });
    dashSyncPeriodRangeControls(toolbar, periodRange, ctx.maxFiscalPeriod ?? 1);
  }

  const revenueEl = wrap.querySelector('.dashboard-sidebar-revenue');
  const expenseEl = wrap.querySelector('.dashboard-sidebar-expense');
  const mainChartEl = wrap.querySelector('.dashboard-chart-main');
  const profitChartEl = wrap.querySelector('.dashboard-chart-profit');
  const cashChartEl = wrap.querySelector('.dashboard-chart-cash');

  const persistCheckedKeys = () => {
    dashSaveCheckedKeys(periodStorageKey, state.checkedKeys);
  };

  const revenueKeySet = new Set(revenueItems.map((i) => i.key));

  const refreshAfterCheckedKeysChange = () => {
    dashRenderDashboardContent(wrap, dashMakeDashboardRenderCtx(dashboardMountCtx ?? ctx), {
      preserveSidebars: true,
      skipUnaffectedCharts: true,
    });
  };

  const onToggle = (key, checked) => {
    if (checked) state.checkedKeys.add(key);
    else state.checkedKeys.delete(key);
    if (revenueKeySet.has(key)) {
      state.revenueCheckAll = dashIsSideFullyChecked(state.checkedKeys, revenueItems);
    } else {
      state.expenseCheckAll = dashIsSideFullyChecked(state.checkedKeys, expenseItems);
    }
    persistCheckedKeys();
    refreshAfterCheckedKeysChange();
  };

  const onRevenueBreakdownModeChange = (mode) => {
    if (state.revenueBreakdownMode === mode) return;
    state.revenueBreakdownMode = mode;
    dashRenderDashboardContent(wrap, dashMakeDashboardRenderCtx(dashboardMountCtx ?? ctx));
  };

  const onExpenseBreakdownModeChange = (mode) => {
    if (state.expenseBreakdownMode === mode) return;
    state.expenseBreakdownMode = mode;
    dashRenderDashboardContent(wrap, dashMakeDashboardRenderCtx(dashboardMountCtx ?? ctx));
  };

  const onRevenueSortModeChange = (mode) => {
    if (state.revenueSortMode === mode) return;
    state.revenueSortMode = mode;
    dashRenderDashboardContent(wrap, dashMakeDashboardRenderCtx(dashboardMountCtx ?? ctx));
  };

  const onExpenseSortModeChange = (mode) => {
    if (state.expenseSortMode === mode) return;
    state.expenseSortMode = mode;
    dashRenderDashboardContent(wrap, dashMakeDashboardRenderCtx(dashboardMountCtx ?? ctx));
  };

  const makeBulkHandlers = (itemKeys, side) => ({
    onCheckAll: () => {
      for (const key of itemKeys) state.checkedKeys.add(key);
      if (side === 'revenue') state.revenueCheckAll = true;
      else state.expenseCheckAll = true;
      persistCheckedKeys();
      refreshAfterCheckedKeysChange();
    },
    onUncheckAll: () => {
      for (const key of itemKeys) state.checkedKeys.delete(key);
      if (side === 'revenue') state.revenueCheckAll = false;
      else state.expenseCheckAll = false;
      persistCheckedKeys();
      refreshAfterCheckedKeysChange();
    },
    onSolo: (key) => {
      if (dashIsSoloCheckedKeys(state.checkedKeys, itemKeys, key)) {
        for (const k of itemKeys) state.checkedKeys.add(k);
        if (side === 'revenue') state.revenueCheckAll = true;
        else state.expenseCheckAll = true;
      } else {
        for (const k of itemKeys) state.checkedKeys.delete(k);
        state.checkedKeys.add(key);
        if (side === 'revenue') state.revenueCheckAll = false;
        else state.expenseCheckAll = false;
      }
      persistCheckedKeys();
      refreshAfterCheckedKeysChange();
    },
  });

  const revenueBulk = makeBulkHandlers(revenueItems.map((i) => i.key), 'revenue');
  const expenseBulk = makeBulkHandlers(expenseItems.map((i) => i.key), 'expense');

  const revenueColorMap = dashBuildItemColorMap(revenueItems);
  const expenseColorMap = dashBuildItemColorMap(expenseItems);

  const makeSidebarChartModeHandlers = (mode) => ({
    ensureChartMode: () => {
      state.chartMode = mode;
    },
  });

  const revenueChartMode = makeSidebarChartModeHandlers('revenue');
  const expenseChartMode = makeSidebarChartModeHandlers('expense');

  const revenueItemKeys = revenueItems.map((item) => item.key);
  const expenseItemKeys = expenseItems.map((item) => item.key);
  const expensePieItems = expenseItems.filter((item) => item.total > 0);
  const canPreserveSidebars = preserveSidebars
    && revenueEl?.querySelector('.dashboard-sidebar-list')
    && expenseEl?.querySelector('.dashboard-sidebar-list')
    && revenueEl?.querySelector('.dashboard-sidebar-pie')
    && expenseEl?.querySelector('.dashboard-sidebar-pie');

  if (canPreserveSidebars) {
    dashSyncSidebarCheckState(revenueEl, state.checkedKeys, revenueItemKeys);
    dashSyncSidebarCheckState(expenseEl, state.checkedKeys, expenseItemKeys);
    dashRenderSidebarPieChart(
      revenueEl.querySelector('.dashboard-sidebar-pie'),
      revenueItems,
      state.checkedKeys,
      revenueColorMap,
      {
        highlightWrap: state.chartMode === 'revenue' ? wrap : null,
        highlightSidebarRoot: state.chartMode === 'revenue' ? revenueEl : null,
        centerTitleLines: DASHBOARD_PIE_CENTER_REVENUE_LINES,
        itemKeys: revenueItemKeys,
        onSolo: (key) => {
          revenueChartMode.ensureChartMode();
          revenueBulk.onSolo(key);
        },
        onShowAll: () => {
          revenueChartMode.ensureChartMode();
          revenueBulk.onCheckAll();
        },
        onHide: (key) => {
          revenueChartMode.ensureChartMode();
          onToggle(key, false);
        },
        animate: false,
      },
    );
    dashRenderSidebarPieChart(
      expenseEl.querySelector('.dashboard-sidebar-pie'),
      expensePieItems,
      state.checkedKeys,
      expenseColorMap,
      {
        highlightWrap: state.chartMode === 'expense' ? wrap : null,
        highlightSidebarRoot: state.chartMode === 'expense' ? expenseEl : null,
        centerTitleLines: DASHBOARD_PIE_CENTER_EXPENSE_LINES,
        itemKeys: expenseItemKeys,
        onSolo: (key) => {
          expenseChartMode.ensureChartMode();
          expenseBulk.onSolo(key);
        },
        onShowAll: () => {
          expenseChartMode.ensureChartMode();
          expenseBulk.onCheckAll();
        },
        onHide: (key) => {
          expenseChartMode.ensureChartMode();
          onToggle(key, false);
        },
        animate: false,
      },
    );
  } else {
    dashRenderSidebarList(revenueEl, revenueItems, state.checkedKeys, '収益合計', 'dashboard-sidebar-header--revenue', onToggle, {
      highlightWrap: state.chartMode === 'revenue' ? wrap : null,
      highlightSidebarRoot: state.chartMode === 'revenue' ? revenueEl : null,
      showBreakdownToggle: true,
      breakdownMode: revenueBreakdownMode,
      onBreakdownModeChange: onRevenueBreakdownModeChange,
      showSortToggle: true,
      sortMode: revenueSortMode,
      onSortModeChange: onRevenueSortModeChange,
      drilldownCtx,
      colorMap: revenueColorMap,
      pieCenterTitleLines: DASHBOARD_PIE_CENTER_REVENUE_LINES,
      animate,
      scrollStateKey: 'revenueListScrollTop',
      ...revenueBulk,
      ...revenueChartMode,
    });
    dashRenderSidebarList(expenseEl, expenseItems, state.checkedKeys, '支出合計', 'dashboard-sidebar-header--expense', onToggle, {
      highlightWrap: state.chartMode === 'expense' ? wrap : null,
      highlightSidebarRoot: state.chartMode === 'expense' ? expenseEl : null,
      showBreakdownToggle: true,
      breakdownMode: expenseBreakdownMode,
      onBreakdownModeChange: onExpenseBreakdownModeChange,
      showSortToggle: true,
      sortMode: expenseSortMode,
      onSortModeChange: onExpenseSortModeChange,
      drilldownCtx,
      colorMap: expenseColorMap,
      pieCenterTitleLines: DASHBOARD_PIE_CENTER_EXPENSE_LINES,
      animate,
      scrollStateKey: 'expenseListScrollTop',
      ...expenseBulk,
      ...expenseChartMode,
      deductionLabel: DASHBOARD_EXPENSE_DEDUCTION_LABEL,
    });
  }

  // 収支推移はチェック対象外。チェック変更時は積み上げ棒だけ更新する
  if (!(skipUnaffectedCharts && state.chartMode === 'balance')) {
    if (state.chartMode === 'balance') {
      const revenueColors = dashGetSidebarHeaderColors('revenue');
      const expenseColors = dashGetSidebarHeaderColors('expense');
      dashRenderSvgGroupedBarChart(
        mainChartEl,
        [
          { values: monthly.map((m) => m.inflow), color: revenueColors.background, label: '収入' },
          { values: monthly.map((m) => m.outflow), color: expenseColors.background, label: '支出' },
        ],
        monthLabels,
        {
          title: '収支推移',
          headerClass: 'dashboard-chart-title--month-row',
          legend: [
            { label: '収入', color: revenueColors.background },
            { label: '支出', color: expenseColors.background },
          ],
          drilldownCtx,
          animate: mainChartAnimate,
        },
      );
    } else if (state.chartMode === 'revenue') {
      const series = dashBuildStackedSeries(revenueItems, state.checkedKeys, revenueColorMap);
      dashRenderSvgStackedBarChart(mainChartEl, series, monthLabels, {
        title: '収益推移',
        headerClass: 'dashboard-chart-title--revenue',
        highlightWrap: wrap,
        highlightSidebarRoot: revenueEl,
        breakdownItems: revenueItems,
        drilldownCtx,
        checkedKeys: state.checkedKeys,
        itemKeys: revenueItemKeys,
        onSolo: revenueBulk.onSolo,
        onShowAll: revenueBulk.onCheckAll,
        onHide: (key) => onToggle(key, false),
        animate: mainChartAnimate,
      });
    } else {
      const series = dashBuildStackedSeries(expenseItems, state.checkedKeys, expenseColorMap);
      dashRenderSvgStackedBarChart(mainChartEl, series, monthLabels, {
        title: '支出推移',
        headerClass: 'dashboard-chart-title--expense',
        highlightWrap: wrap,
        highlightSidebarRoot: expenseEl,
        breakdownItems: expenseItems,
        drilldownCtx,
        checkedKeys: state.checkedKeys,
        itemKeys: expenseItemKeys,
        onSolo: expenseBulk.onSolo,
        onShowAll: expenseBulk.onCheckAll,
        onHide: (key) => onToggle(key, false),
        animate: mainChartAnimate,
      });
    }
  }

  // 棒グラフ更新後に結び直す（空→全表示のあとでもリスト→棒のハイライトが生きるように）
  dashBindSidebarListSeriesHighlight(revenueEl, 'revenue');
  dashBindSidebarListSeriesHighlight(expenseEl, 'expense');

  if (!skipUnaffectedCharts) {
    dashRenderSvgGradientLineChart(
      profitChartEl,
      monthly.map((m) => m.profit),
      monthLabels,
      {
        title: '利益率推移',
        headerClass: 'dashboard-chart-title--profit',
        sectionFilterId: 'profit',
        includeZero: true,
        negativeTicksRed: true,
        prevValues: prevMonthly?.map((m) => m.profit) ?? null,
        prevPrevValues: prevPrevMonthly?.map((m) => m.profit) ?? null,
        animate,
      },
    );

    dashRenderSvgGradientLineChart(
      cashChartEl,
      monthly.map((m) => m.cash),
      monthLabels,
      {
        title: '預金残高推移',
        headerClass: 'dashboard-chart-title--cash',
        sectionFilterId: 'cashBalance',
        includeZero: false,
        prevValues: prevMonthly?.map((m) => m.cash) ?? null,
        prevPrevValues: prevPrevMonthly?.map((m) => m.cash) ?? null,
        animate,
      },
    );
  }
}

function dashMakeDashboardRenderCtx({
  data,
  prevData,
  prevPrevData,
  allPeriods,
  periodRange,
  maxFiscalPeriod,
  appSettings,
  state,
  showJournalPopup,
  hasJournalDrilldown,
}) {
  return {
    data,
    prevData,
    prevPrevData,
    allPeriods,
    periodRange,
    maxFiscalPeriod,
    appSettings,
    state,
    showJournalPopup,
    hasJournalDrilldown,
  };
}

function dashSwitchToChartMode(wrap, mode) {
  const ctx = dashboardMountCtx;
  if (!ctx || !wrap?.isConnected) return;
  // 状態とタブ表示が食い違う場合は、同モードでも再描画する
  const activeBtn = wrap.querySelector('.dashboard-mode-tabs .dashboard-mode-btn.is-active');
  const uiMode = activeBtn?.dataset?.mode;
  if (ctx.state.chartMode === mode && uiMode === mode) return;
  ctx.state.chartMode = mode;
  dashRenderDashboardContent(wrap, dashMakeDashboardRenderCtx(ctx), { animateMainChart: true });
}

const DASH_CLICK_ROUTE_INTERACTIVE =
  'button, input, select, textarea, a,'
  + ' .plan-row-context-menu, .plan-main-menu-panel, .plan-period-select-panel,'
  + ' [role="menu"], [role="listbox"]';
const DASH_SIDEBAR_ROW_CONTROLS =
  '.dashboard-sidebar-check, .dashboard-sidebar-name, .dashboard-sidebar-amount';
const DASH_MAIN_CHART = '.dashboard-chart-main';
const DASH_SIDEBAR = '.dashboard-sidebar';

function dashIsDashboardClickInteractive(ev) {
  return Boolean(ev.target.closest(DASH_CLICK_ROUTE_INTERACTIVE));
}

function dashEventPathMatches(ev, selector) {
  for (const node of ev.composedPath()) {
    if (node instanceof Element && node.matches(selector)) return true;
  }
  return false;
}

function dashIsSidebarClick(ev) {
  // 行クリックでサイドバーが再描画されると target が DOM から外れ closest が効かなくなる
  return dashEventPathMatches(ev, DASH_SIDEBAR);
}

function dashIsSidebarRowControlClick(ev) {
  return dashEventPathMatches(ev, DASH_SIDEBAR_ROW_CONTROLS);
}

function dashIsMainChartClick(ev) {
  return Boolean(ev.target.closest(DASH_MAIN_CHART));
}

function dashUnbindDashboardClickRouting() {
  dashBalanceClickCleanup?.();
  dashBalanceClickCleanup = null;
}

function dashBindDashboardClickRouting(wrap, { revenueEl, expenseEl }) {
  dashUnbindDashboardClickRouting();
  const planApp = document.querySelector('.plan-app');
  if (!planApp) return;

  const controller = new AbortController();
  const { signal } = controller;
  dashBalanceClickCleanup = () => controller.abort();

  planApp.addEventListener('click', (ev) => {
    if (!dashboardMountCtx || !wrap.isConnected) return;
    if (dashIsDashboardClickInteractive(ev) || dashIsMainChartClick(ev) || dashIsSidebarClick(ev)) return;
    dashSwitchToChartMode(wrap, 'balance');
  }, { signal });

  const bindSidebarOverride = (el, mode) => {
    el?.addEventListener('click', (ev) => {
      if (!dashboardMountCtx || !wrap.isConnected) return;
      if (dashIsDashboardClickInteractive(ev) || dashIsSidebarRowControlClick(ev)) return;
      ev.stopPropagation();
      dashSwitchToChartMode(wrap, mode);
    }, { signal });
  };
  bindSidebarOverride(revenueEl, 'revenue');
  bindSidebarOverride(expenseEl, 'expense');
}

function mountDashboardPanel({
  replaceRootPanel,
  data,
  prevData = null,
  prevPrevData = null,
  allPeriods = null,
  periodRange = { from: 1, to: 1 },
  maxFiscalPeriod = 1,
  onPeriodRangeChange = null,
  appSettings,
  getSectionFilterColors = null,
  showJournalPopup = null,
  hasJournalDrilldown = null,
}) {
  if (!data) return;

  dashSetFiscalContext(data);

  const prevCtx = dashboardMountCtx;
  const periodKey = allPeriods?.length
    ? dashMultiPeriodStorageKey(periodRange.from, periodRange.to)
    : periodRange.from;
  const prevPeriodKey = prevCtx == null
    ? null
    : (prevCtx.allPeriods?.length
      ? dashMultiPeriodStorageKey(prevCtx.periodRange.from, prevCtx.periodRange.to)
      : prevCtx.periodRange?.from ?? prevCtx.appSettings?.fiscalPeriod);
  const periodChanged = prevCtx != null && prevPeriodKey !== periodKey;

  const state = prevCtx?.state ?? {
    chartMode: 'balance',
    revenueBreakdownMode: DASHBOARD_DEFAULT_REVENUE_BREAKDOWN_MODE,
    expenseBreakdownMode: DASHBOARD_DEFAULT_EXPENSE_BREAKDOWN_MODE,
    revenueSortMode: DASHBOARD_DEFAULT_SORT_MODE,
    expenseSortMode: DASHBOARD_DEFAULT_SORT_MODE,
    checkedKeys: new Set(),
    seenKeys: new Set(),
    revenueCheckAll: true,
    expenseCheckAll: true,
    lastRevenueItems: null,
    lastExpenseItems: null,
    lastRevenueBreakdownMode: null,
    lastExpenseBreakdownMode: null,
    lastAnimatedPeriod: null,
    initialized: false,
  };
  if (periodChanged) {
    state.pendingPeriodRemap = true;
  }

  const shouldAnimate = state.lastAnimatedPeriod !== periodKey;
  if (shouldAnimate) {
    state.lastAnimatedPeriod = periodKey;
  }

  dashboardMountCtx = {
    state,
    appSettings,
    data,
    prevData,
    prevPrevData,
    allPeriods,
    periodRange,
    maxFiscalPeriod,
    getSectionFilterColors,
    showJournalPopup,
    hasJournalDrilldown,
  };

  const renderCtx = dashMakeDashboardRenderCtx({
    data,
    prevData,
    prevPrevData,
    allPeriods,
    periodRange,
    maxFiscalPeriod,
    appSettings,
    state,
    showJournalPopup,
    hasJournalDrilldown,
  });

  const wrap = document.createElement('div');
  wrap.className = 'dashboard-wrap';

  const toolbar = document.createElement('div');
  toolbar.className = 'dashboard-toolbar';
  toolbar.innerHTML = `
    <div class="dashboard-toolbar-left">
      <h2 class="dashboard-title"></h2>
      <div class="dashboard-toolbar-controls">
        <div class="dashboard-mode-tabs" role="tablist">
          ${DASHBOARD_CHART_MODES.map(
    (mode) => `<button type="button" class="dashboard-mode-btn" data-mode="${mode.id}" role="tab" title="${mode.title}">${mode.label}</button>`,
  ).join('')}
        </div>
        <div class="dashboard-period-override-group">
          <span class="dashboard-period-override-label" title="${TIP_DASH_PERIOD_OVERRIDE}">${DASHBOARD_PERIOD_OVERRIDE_LABEL}</span>
          <div class="dashboard-period-range-controls">
            <select
              class="app-settings-input dashboard-period-range-select dashboard-period-range-from"
              aria-label="開始期"
              title="${TIP_DASH_PERIOD_FROM}"
            ></select>
            <span class="dashboard-period-range-sep" aria-hidden="true">〜</span>
            <select
              class="app-settings-input dashboard-period-range-select dashboard-period-range-to"
              aria-label="終了期"
              title="${TIP_DASH_PERIOD_TO}"
            ></select>
            <button
              type="button"
              class="dashboard-mode-btn dashboard-period-all-btn"
              title="${TIP_DASH_ALL_PERIODS}"
            >${DASHBOARD_ALL_PERIODS_BTN_LABEL}</button>
          </div>
        </div>
      </div>
    </div>`;

  const grid = document.createElement('div');
  grid.className = 'dashboard-grid';
  grid.innerHTML = `
    <aside class="dashboard-sidebar dashboard-sidebar-revenue"></aside>
    <section class="dashboard-main">
      <div class="dashboard-chart-main"></div>
      <div class="dashboard-charts-bottom">
        <div class="dashboard-chart-profit"></div>
        <div class="dashboard-chart-cash"></div>
      </div>
    </section>
    <aside class="dashboard-sidebar dashboard-sidebar-expense"></aside>`;

  wrap.append(toolbar, grid);
  replaceRootPanel(wrap);

  dashBindDashboardClickRouting(wrap, {
    revenueEl: grid.querySelector('.dashboard-sidebar-revenue'),
    expenseEl: grid.querySelector('.dashboard-sidebar-expense'),
  });

  dashBindPeriodRangeControls(toolbar, {
    periodRange,
    maxFiscalPeriod,
    onPeriodRangeChange,
  });

  toolbar.querySelectorAll('.dashboard-mode-tabs .dashboard-mode-btn').forEach((btn) => {
    btn.addEventListener('click', () => {
      state.chartMode = btn.dataset.mode;
      dashRenderDashboardContent(wrap, renderCtx, { animateMainChart: true });
    });
  });

  dashRenderDashboardContent(wrap, renderCtx, { animate: shouldAnimate });

  // 主エリアの寸法が変わったらチャートを実測サイズで再描画（余白の無駄・引き伸ばしを防ぐ）
  const mainEl = grid.querySelector('.dashboard-main');
  let lastMainWidth = mainEl.clientWidth;
  let lastMainHeight = mainEl.clientHeight;
  let resizeRaf = null;
  const resizeObserver = new ResizeObserver(() => {
    if (!wrap.isConnected) {
      resizeObserver.disconnect();
      return;
    }
    if (Math.abs(mainEl.clientWidth - lastMainWidth) < 2
      && Math.abs(mainEl.clientHeight - lastMainHeight) < 2) {
      return;
    }
    lastMainWidth = mainEl.clientWidth;
    lastMainHeight = mainEl.clientHeight;
    if (resizeRaf != null) cancelAnimationFrame(resizeRaf);
    resizeRaf = requestAnimationFrame(() => {
      resizeRaf = null;
      if (!wrap.isConnected) return;
      lastMainWidth = mainEl.clientWidth;
      lastMainHeight = mainEl.clientHeight;
      dashRenderDashboardContent(wrap, dashMakeDashboardRenderCtx(dashboardMountCtx));
    });
  });
  resizeObserver.observe(mainEl);
}

function resetDashboardState({ fiscalPeriod = null, multiPeriodRange = null } = {}) {
  dashUnbindDashboardClickRouting();
  dashboardMountCtx = null;
  if (fiscalPeriod != null) dashClearCheckedKeys(fiscalPeriod);
  if (multiPeriodRange) {
    dashClearCheckedKeys(dashMultiPeriodStorageKey(multiPeriodRange.from, multiPeriodRange.to));
  }
}

/* ui/taxForecastSettingsUi.js */
function formatYenInputValue(value) {
  const digits = String(value ?? '').replace(/[^\d]/g, '');
  if (!digits) return '';
  const num = parseInt(digits, 10);
  if (!Number.isFinite(num)) return '';
  return `\u00a5${num.toLocaleString('ja-JP')}`;
}

function parseYenInputValue(raw) {
  return String(raw ?? '').replace(/[^\d]/g, '');
}

function filterIntegerInput(value) {
  return String(value ?? '').replace(/[^\d]/g, '');
}

function bindYenInput(input, { onChange } = {}) {
  if (!input) return;
  input.type = 'text';
  input.inputMode = 'numeric';
  input.autocomplete = 'off';
  input.spellcheck = false;
  input.classList.add('tax-forecast-input--currency');

  input.addEventListener('focus', () => {
    input.value = parseYenInputValue(input.value);
  });

  input.addEventListener('input', () => {
    const filtered = filterIntegerInput(input.value);
    if (filtered !== input.value) input.value = filtered;
  });

  input.addEventListener('blur', () => {
    input.value = formatYenInputValue(input.value);
    onChange?.();
    input.dispatchEvent(new Event('change', { bubbles: true }));
  });
}

function setYenInputValue(input, value) {
  if (!input) return;
  input.value = formatYenInputValue(value);
}

function readYenInputValue(input) {
  if (!input) return '';
  if (input.dataset.masked === '1' && input.dataset.storedValue != null) {
    return String(input.dataset.storedValue);
  }
  return parseYenInputValue(input?.value);
}

const TAX_FORECAST_MASK_DISPLAY = '—';
const TAX_FORECAST_MASK_SELECT_VALUE = '__tax_forecast_masked__';

function ensureSelectMaskOption(select) {
  let opt = select.querySelector('option[data-mask-placeholder]');
  if (!opt) {
    opt = document.createElement('option');
    opt.value = TAX_FORECAST_MASK_SELECT_VALUE;
    opt.textContent = TAX_FORECAST_MASK_DISPLAY;
    opt.dataset.maskPlaceholder = '1';
    select.insertBefore(opt, select.firstChild);
  }
  return opt;
}

function maskControl(el) {
  if (!el || el.dataset.masked === '1') return;
  if (el.tagName === 'SELECT') {
    el.dataset.storedValue = el.value;
    ensureSelectMaskOption(el);
    el.value = TAX_FORECAST_MASK_SELECT_VALUE;
  } else if (el.classList.contains('tax-forecast-input--currency')) {
    el.dataset.storedValue = parseYenInputValue(el.value);
    el.value = TAX_FORECAST_MASK_DISPLAY;
  } else {
    el.dataset.storedValue = el.value;
    el.value = TAX_FORECAST_MASK_DISPLAY;
  }
  el.dataset.masked = '1';
  el.disabled = true;
}

function unmaskControl(el) {
  if (!el) return;
  if (el.tagName === 'SELECT') {
    el.querySelector('option[data-mask-placeholder]')?.remove();
    if (el.dataset.masked === '1') {
      if (el.dataset.storedValue != null) {
        el.value = el.dataset.storedValue;
      }
      delete el.dataset.storedValue;
      delete el.dataset.masked;
    }
    el.disabled = false;
    return;
  }
  if (el.dataset.masked === '1') {
    const raw = el.dataset.storedValue ?? '';
    if (el.classList.contains('tax-forecast-input--currency')) {
      el.value = raw === '' ? '' : formatYenInputValue(raw);
    } else {
      el.value = raw;
    }
    delete el.dataset.storedValue;
    delete el.dataset.masked;
  }
  el.disabled = false;
}

function readControlValue(el) {
  if (!el) return '';
  if (el.dataset.masked === '1' && el.dataset.storedValue != null) {
    return el.dataset.storedValue;
  }
  if (el.type === 'checkbox') return el.checked;
  return el.value;
}

function isCashReferencedSource(source) {
  return source === 'bs' || source === 'plan';
}

/** 金額表示。computed のとき手前に小さい ∑ を付ける（アプリ計算であることを示す） */
function yen(value, formatYen, { computed = false } = {}) {
  if (value == null || !Number.isFinite(value)) return '—';
  const amount = `¥${formatYen(value)}`;
  if (!computed) return amount;
  return `<span class="tax-forecast-computed-prefix" title="アプリが計算した金額">∑</span> ${amount}`;
}

function isScheduleAmountComputed(row, cashSource) {
  if (!row) return false;
  if (row.kind === 'provisional' || row.kind === 'interim') return true;
  // 確定納付: CSV/未払参照でなければアプリ計算
  return !isCashReferencedSource(cashSource);
}

function isPaymentTotalComputed(schedule, cashSource) {
  if (cashSource === 'exempt') return true;
  const rows = schedule ?? [];
  if (rows.length === 0) return false;
  return rows.some((row) => isScheduleAmountComputed(row, cashSource));
}

function renderScheduleTable(schedule, formatYen, { cashSource = null } = {}) {
  if (!schedule?.length) {
    return `<p class="app-settings-hint tax-forecast-empty">支払予定はありません</p>`;
  }
  const rows = schedule.map((row) => `
    <tr>
      <td>${row.label ?? ''}</td>
      <td>${row.monthLabel ?? ''}</td>
      <td class="tax-forecast-amount tax-forecast-cell--amount">${yen(row.amount, formatYen, {
        computed: isScheduleAmountComputed(row, cashSource),
      })}</td>
    </tr>
  `).join('');
  return `
    <table class="expand-settings-table tax-forecast-schedule-table">
      <thead>
        <tr>
          <th>区分</th>
          <th>支払月</th>
          <th>金額</th>
        </tr>
      </thead>
      <tbody>${rows}</tbody>
    </table>
  `;
}

function renderBasisList(items) {
  if (!items?.length) return '';
  const rows = items.filter(Boolean).map((item) => `
    <li><span class="tax-forecast-basis-label">${item.label}</span><span class="tax-forecast-basis-value">${item.value}</span></li>
  `).join('');
  return `<ul class="tax-forecast-basis-list">${rows}</ul>`;
}

function renderItemizedBreakdownTable(itemized, formatYen) {
  if (!itemized?.breakdown?.length) return '';
  const rows = [
    {
      label: '課税所得（1,000円未満切捨）',
      amount: itemized.taxableIncome,
      emphasis: false,
    },
    ...itemized.breakdown.map((row) => ({
      label: row.label,
      amount: row.amount,
      emphasis: false,
    })),
    {
      label: '法人税等合計',
      amount: itemized.total,
      emphasis: true,
    },
  ].map((row) => `
    <tr${row.emphasis ? ' class="tax-forecast-breakdown-total"' : ''}>
      <td>${row.label}</td>
      <td class="tax-forecast-amount tax-forecast-cell--amount">${yen(row.amount, formatYen, { computed: true })}</td>
    </tr>
  `).join('');
  return `
    <table class="expand-settings-table tax-forecast-breakdown-table">
      <thead>
        <tr>
          <th>税目</th>
          <th>金額</th>
        </tr>
      </thead>
      <tbody>${rows}</tbody>
    </table>
  `;
}

/** 来期納税見込みパネルの HTML を生成する */
function buildTaxForecastPanelHtml(forecast, formatYen, { compact = false } = {}) {
  if (!forecast) {
    return `<p class="app-settings-hint tax-forecast-empty">見込みを計算できません</p>`;
  }
  const warningItems = (forecast.warnings ?? []).map((w) => {
    const text = w === '免税事業者のため消費税の支払見込は0です'
      ? `免税事業者のため消費税の支払見込は${yen(0, formatYen, { computed: true })}です`
      : w;
    return `<p class="tax-forecast-warning">${text}</p>`;
  });
  const warningsHtml = warningItems.length
    ? `<div class="tax-forecast-warnings">${warningItems.join('')}</div>`
    : '';
  const isItemized = forecast.corporateTax?.method === 'itemized';
  const methodLabel = isItemized ? '検算（税目別）' : '簡易（実効税率）';
  const corpCashReferenced = isCashReferencedSource(forecast.corporateTax?.cashSource);
  const consCashReferenced = isCashReferencedSource(forecast.consumptionTax?.cashSource);
  const corpTotalComputed = isPaymentTotalComputed(
    forecast.corporateTax?.schedule,
    forecast.corporateTax?.cashSource,
  );
  const consTotalComputed = isPaymentTotalComputed(
    forecast.consumptionTax?.schedule,
    forecast.consumptionTax?.cashSource,
  );
  const profitBasis = [
    { label: '参照期', value: forecast.currentPeriodLabel },
    { label: '年間見込税引前利益', value: yen(forecast.profitEstimate?.amount, formatYen, { computed: true }) },
    { label: '計算方法', value: forecast.profitEstimate?.basis ?? '' },
    { label: '補足説明', value: forecast.profitEstimate?.detail ?? '' },
    { label: '繰越欠損控除', value: yen(forecast.corporateTax?.lossDeduction, formatYen) },
    {
      label: '事業税・確定納付減算',
      value: yen(forecast.corporateTax?.enterpriseTaxSettlementDeduction, formatYen),
    },
    {
      label: '事業税・予定納税減算',
      value: yen(forecast.corporateTax?.enterpriseTaxProvisionalDeduction, formatYen),
    },
    {
      label: '所得税額の還付（加算）',
      value: yen(forecast.corporateTax?.incomeTaxRefundAddition, formatYen),
    },
    { label: '課税対象利益', value: yen(forecast.taxableProfit, formatYen, { computed: true }) },
    { label: '法人税計算', value: methodLabel },
    { label: '法人区分・税率', value: `${forecast.regionLabel} / ${forecast.corporateTax?.rateLabel ?? ''}` },
    {
      label: '確定納付（期末未払）',
      value: yen(
        forecast.corporateTax?.settlementAmount ?? forecast.corporateTax?.annualAmount,
        formatYen,
        { computed: !corpCashReferenced },
      ),
    },
    {
      label: '年税額（予定・中間の計算基礎）',
      value: yen(forecast.corporateTax?.annualAmount, formatYen, { computed: !corpCashReferenced }),
    },
    { label: '資金基準の出所', value: forecast.corporateTax?.cashSourceLabel ?? '' },
    { label: '検算税額（参考）', value: yen(forecast.corporateTax?.calculatedAmount, formatYen, { computed: true }) },
  ];
  const itemizedBreakdownHtml = isItemized
    ? renderItemizedBreakdownTable(forecast.corporateTax?.itemized, formatYen)
    : '';
  const isConsumptionExempt = Boolean(
    forecast.simulation?.consumptionTaxExempt
    || forecast.consumptionTax?.cashSource === 'exempt',
  );
  const consumptionBasis = [
    {
      label: '確定納付（期末未払）',
      value: yen(
        forecast.consumptionTax?.settlementAmount ?? forecast.consumptionTax?.annualAmount,
        formatYen,
        { computed: !consCashReferenced },
      ),
    },
    {
      label: '年税額（予定・中間の計算基礎）',
      value: yen(forecast.consumptionTax?.annualAmount, formatYen, { computed: !consCashReferenced }),
    },
    { label: '資金基準の出所', value: forecast.consumptionTax?.cashSourceLabel ?? '' },
    {
      label: '売上仕入からの概算（参考）',
      value: yen(forecast.consumptionTax?.estimatedAmount, formatYen, { computed: true }),
    },
    { label: '課税計算方法', value: forecast.consumptionTax?.estimate?.basis ?? '' },
    {
      label: "経理方式",
      value: forecast.consumptionTax?.estimate?.accountingTaxBasisLabel ?? '',
    },
    {
      label: '補足説明',
      value: isConsumptionExempt
        ? `免税事業者のため消費税の支払見込は${yen(0, formatYen, { computed: true })}です`
        : (forecast.consumptionTax?.estimate?.detail ?? ''),
    },
  ];
  const summaryHtml = `
    <div class="tax-forecast-summary-grid${compact ? ' tax-forecast-summary-grid--compact' : ''}">
      <div class="tax-forecast-summary-card" data-section-id="tax">
        <span class="tax-forecast-summary-label">${compact ? '法人税等' : '来期支払合計（法人税等）'}</span>
        <span class="tax-forecast-summary-value">${yen(forecast.corporateTax?.totalPaymentInNextPeriod, formatYen, { computed: corpTotalComputed })}</span>
      </div>
      <div class="tax-forecast-summary-card" data-section-id="otherPay">
        <span class="tax-forecast-summary-label">${compact ? '消費税' : '来期支払合計（消費税）'}</span>
        <span class="tax-forecast-summary-value">${yen(forecast.consumptionTax?.totalPaymentInNextPeriod, formatYen, { computed: consTotalComputed })}</span>
      </div>
      <div class="tax-forecast-summary-card tax-forecast-summary-card--total" data-section-id="cfOut">
        <span class="tax-forecast-summary-label">${compact ? '総計' : '来期支払合計（総計）'}</span>
        <span class="tax-forecast-summary-value">${yen(forecast.grandTotalPaymentInNextPeriod, formatYen, {
          computed: corpTotalComputed || consTotalComputed,
        })}</span>
      </div>
    </div>
  `;
  // 警告・用語注釈（コンパクト時は詳細グリッド右2列の下へ）
  const targetPeriodHtml = `<p class="app-settings-hint tax-forecast-target-period">${forecast.currentPeriodLabel}の見込をもとに、${forecast.nextPeriodLabel}に支払うキャッシュ見込です。</p>`;
  const helpNotesHtml = `
    <div class="tax-forecast-help-notes">
      <p class="app-settings-hint tax-forecast-help-note">※　「当期分　確定納付」は、期末時点の未払（まだ払っていない残額）です。その期内にすでに払った予定納税・中間納税は含まれません。</p>
      <p class="app-settings-hint tax-forecast-help-note">※　「来期　予定納税／中間納税」は、前年の年税額を基礎にした前払の見込です。残額である確定納付より大きくなることがあります。</p>
      <p class="app-settings-hint tax-forecast-help-note">※　この画面の予定・中間は、資金基準の年税額（多くの場合は期末未払。あれば仮払の清算分も加算）から見積ります。予定を費用科目へ直接計上している場合などは、実績より小さく見えることがあります。</p>
      <p class="app-settings-hint tax-forecast-help-note">※　金額の手前の ∑ はアプリが計算した値、∑ なしは貸借の未払など CSV 由来の参照値です。</p>
    </div>
  `;
  const footerNotesInnerHtml = `
    ${warningsHtml}
    ${helpNotesHtml}
  `;
  const footerNotesHtml = `
    ${footerNotesInnerHtml}
    ${compact ? '' : targetPeriodHtml}
  `;
  if (compact) {
    const consumptionBlockHtml = `
        <div class="tax-forecast-detail-block">
          <h4 class="tax-forecast-detail-title">来期の消費税支払スケジュール</h4>
          ${renderScheduleTable(forecast.consumptionTax?.schedule, formatYen, {
            cashSource: forecast.consumptionTax?.cashSource,
          })}
          <h4 class="tax-forecast-detail-title">消費税の計算根拠</h4>
          ${renderBasisList(consumptionBasis)}
        </div>`;
    const itemizedBlockHtml = itemizedBreakdownHtml ? `
        <div class="tax-forecast-detail-block">
          <h4 class="tax-forecast-detail-title">法人税等の内訳（検算）</h4>
          ${itemizedBreakdownHtml}
        </div>` : '';
    // 右列に消費税・内訳＋注釈をまとめ、注釈を直下に詰める
    return `
      ${summaryHtml}
      <div class="tax-forecast-detail-grid tax-forecast-detail-grid--compact${itemizedBreakdownHtml ? ' tax-forecast-detail-grid--with-notes-right' : ''}">
        <div class="tax-forecast-detail-block">
          <h4 class="tax-forecast-detail-title">来期の法人税支払スケジュール</h4>
          ${renderScheduleTable(forecast.corporateTax?.schedule, formatYen, {
            cashSource: forecast.corporateTax?.cashSource,
          })}
          <h4 class="tax-forecast-detail-title">法人税の計算根拠</h4>
          ${renderBasisList(profitBasis)}
        </div>
        <div class="tax-forecast-detail-right">
          <div class="tax-forecast-detail-right-top${itemizedBreakdownHtml ? ' tax-forecast-detail-right-top--two' : ''}">
            ${consumptionBlockHtml}
            ${itemizedBlockHtml}
          </div>
          <div class="tax-forecast-detail-notes">
            ${footerNotesInnerHtml}
          </div>
        </div>
      </div>
    `;
  }
  return `
    ${summaryHtml}
    <div class="tax-forecast-detail-grid">
      <div class="tax-forecast-detail-block">
        <h4 class="tax-forecast-detail-title">来期の法人税支払スケジュール</h4>
        ${renderScheduleTable(forecast.corporateTax?.schedule, formatYen, {
          cashSource: forecast.corporateTax?.cashSource,
        })}
        <h4 class="tax-forecast-detail-title">法人税の計算根拠</h4>
        ${renderBasisList(profitBasis)}
        ${itemizedBreakdownHtml ? `<h4 class="tax-forecast-detail-title">法人税等の内訳（検算）</h4>${itemizedBreakdownHtml}` : ''}
      </div>
      <div class="tax-forecast-detail-block">
        <h4 class="tax-forecast-detail-title">来期の消費税支払スケジュール</h4>
        ${renderScheduleTable(forecast.consumptionTax?.schedule, formatYen, {
          cashSource: forecast.consumptionTax?.cashSource,
        })}
        <h4 class="tax-forecast-detail-title">消費税の計算根拠</h4>
        ${renderBasisList(consumptionBasis)}
      </div>
    </div>
    ${footerNotesHtml}
  `;
}

function computeTaxForecastForDisplay({
  getForecastContext,
  appSettings,
  getAppSettings,
}) {
  const settings = getAppSettings?.() ?? appSettings;
  const ctx = getForecastContext?.();
  if (!ctx) return null;
  const fiscalEndMonth = ctx.fiscalEndMonth ?? 12;
  return computeNextPeriodTaxForecast({
    ...ctx,
    taxSimulation: normalizeTaxSimulation(settings?.taxSimulation, fiscalEndMonth),
    consumptionTaxRates: settings?.consumptionTaxRates,
    accountingTaxBasis: settings?.accountingTaxBasis,
  });
}

function buildMonthSelectOptions(fiscalMonths, selectedIndex) {
  return fiscalMonths.map((label, index) => {
    const selected = index === selectedIndex ? ' selected' : '';
    return `<option value="${index}"${selected}>${label}</option>`;
  }).join('');
}

/** 来期納税見込みのシミュレーション設定フォームをマウントする */
